#!/usr/bin/env bash
# =============================================================================
# LSSHM - Local SSH Manager
# Version: 0.3.0
# Built:   2026-07-18T19:57:51Z
#
# This file is generated by scripts/build.sh from the modules in src/.
# Do not edit it by hand; edit the modules and rebuild.
#
# A simple local OpenSSH server, client, user access and key management tool
# for Linux (Windows support is planned through lsshm.ps1).
# =============================================================================

set -euo pipefail


# ===== src/common.sh ===================================================
# shellcheck shell=bash
# =============================================================================
# common.sh - shared helpers: version, paths, logging, prompts, temp files
# =============================================================================
# This module has no dependencies on other LSSHM modules and must be sourced
# (or concatenated) first.

# The build script replaces the token below with the content of the VERSION
# file. When running directly from src/ the token stays literal and the guard
# below falls back to a development version string.
LSSHM_VERSION="0.3.0"
case "$LSSHM_VERSION" in
    *@@*) LSSHM_VERSION="0.3.0-dev" ;;
esac

LSSHM_NAME="LSSHM"
LSSHM_LONG_NAME="LSSHM - Local SSH Manager"
LSSHM_REPO_RAW="${LSSHM_REPO_RAW:-https://raw.githubusercontent.com/sannier3/lsshm/main}"

# -----------------------------------------------------------------------------
# XDG base directories
# -----------------------------------------------------------------------------
lsshm_init_paths() {
    LSSHM_HOME="${HOME:-/root}"
    LSSHM_XDG_CONFIG="${XDG_CONFIG_HOME:-$LSSHM_HOME/.config}"
    LSSHM_XDG_DATA="${XDG_DATA_HOME:-$LSSHM_HOME/.local/share}"
    LSSHM_XDG_STATE="${XDG_STATE_HOME:-$LSSHM_HOME/.local/state}"
    LSSHM_XDG_CACHE="${XDG_CACHE_HOME:-$LSSHM_HOME/.cache}"
    LSSHM_BIN_DIR="$LSSHM_HOME/.local/bin"

    LSSHM_CONFIG_DIR="$LSSHM_XDG_CONFIG/lsshm"
    LSSHM_DATA_DIR="$LSSHM_XDG_DATA/lsshm"
    LSSHM_STATE_DIR="$LSSHM_XDG_STATE/lsshm"
    LSSHM_CACHE_DIR="$LSSHM_XDG_CACHE/lsshm"

    LSSHM_CONFIG_FILE="$LSSHM_CONFIG_DIR/config"
    LSSHM_BACKUP_DIR="$LSSHM_STATE_DIR/backups"
    LSSHM_LOG_FILE="$LSSHM_STATE_DIR/lsshm.log"
    LSSHM_INSTALL_TARGET="$LSSHM_DATA_DIR/lsshm.sh"
    LSSHM_BIN_LINK="$LSSHM_BIN_DIR/lsshm"
}

# -----------------------------------------------------------------------------
# Colors (disabled when not writing to a terminal or NO_COLOR is set)
# -----------------------------------------------------------------------------
lsshm_init_colors() {
    if [ -t 1 ] && [ -z "${NO_COLOR:-}" ] && [ "${LSSHM_NO_COLOR:-0}" != "1" ] \
        && [ "${LSSHM_UI_MODE:-0}" != "1" ]; then
        LSSHM_C_RESET="$(printf '\033[0m')"
        LSSHM_C_BOLD="$(printf '\033[1m')"
        LSSHM_C_DIM="$(printf '\033[2m')"
        LSSHM_C_RED="$(printf '\033[31m')"
        LSSHM_C_GREEN="$(printf '\033[32m')"
        LSSHM_C_YELLOW="$(printf '\033[33m')"
    else
        LSSHM_C_RESET=""; LSSHM_C_BOLD=""; LSSHM_C_DIM=""
        LSSHM_C_RED=""; LSSHM_C_GREEN=""; LSSHM_C_YELLOW=""
    fi
}

# Remove ANSI escape sequences (dialog and programbox do not render them).
lsshm_strip_ansi() {
    sed $'s/\033\\[[0-9;]*[a-zA-Z]//g'
}

lsshm_strip_ansi_file() {
    local f="$1" tmp
    tmp="$(lsshm_mktemp)"
    lsshm_strip_ansi <"$f" >"$tmp" && mv "$tmp" "$f"
}

# -----------------------------------------------------------------------------
# Logging
# -----------------------------------------------------------------------------
lsshm_log() {
    # lsshm_log LEVEL MESSAGE...
    local level="$1"; shift
    local msg="$*"
    if [ -n "${LSSHM_LOG_FILE:-}" ]; then
        local dir; dir="$(dirname "$LSSHM_LOG_FILE")"
        if [ -d "$dir" ] || mkdir -p "$dir" 2>/dev/null; then
            printf '%s [%s] %s\n' "$(date '+%Y-%m-%dT%H:%M:%S%z')" "$level" "$msg" \
                >>"$LSSHM_LOG_FILE" 2>/dev/null || true
        fi
    fi
}

lsshm_info()  { printf '%s\n' "$*"; lsshm_log INFO "$*"; }
lsshm_note()  { printf '%s%s%s\n' "${LSSHM_C_DIM:-}" "$*" "${LSSHM_C_RESET:-}" >&2; lsshm_log INFO "$*"; }
lsshm_ok()    { printf '%s%s%s\n' "${LSSHM_C_GREEN:-}" "$*" "${LSSHM_C_RESET:-}"; lsshm_log OK "$*"; }
lsshm_warn()  { printf '%s%s%s\n' "${LSSHM_C_YELLOW:-}" "$*" "${LSSHM_C_RESET:-}" >&2; lsshm_log WARN "$*"; }
lsshm_error() { printf '%s%s%s\n' "${LSSHM_C_RED:-}" "$*" "${LSSHM_C_RESET:-}" >&2; lsshm_log ERROR "$*"; }

lsshm_die() {
    lsshm_error "$*"
    exit 1
}

lsshm_header() {
    printf '%s%s%s\n' "${LSSHM_C_BOLD:-}" "$LSSHM_LONG_NAME" "${LSSHM_C_RESET:-}"
    printf '%sv%s%s\n\n' "${LSSHM_C_DIM:-}" "$LSSHM_VERSION" "${LSSHM_C_RESET:-}"
}

# -----------------------------------------------------------------------------
# Prompts
# -----------------------------------------------------------------------------
# True when stdin/stdout is a TTY, or when /dev/tty is available (IDE
# terminals, sudo, Git Bash on Windows often lack -t 0 but still have /dev/tty).
lsshm_have_tty() {
    [ -e /dev/tty ] 2>/dev/null && [ -r /dev/tty ] && [ -w /dev/tty ]
}

lsshm_is_interactive() {
    [ "${LSSHM_ASSUME_YES:-0}" != "1" ] || return 1
    [ -t 0 ] && [ -t 1 ] && return 0
    lsshm_have_tty && return 0
    return 1
}

lsshm_require_interactive() {
    if lsshm_is_interactive; then
        return 0
    fi
    lsshm_error "Un terminal interactif est requis pour le menu."
    lsshm_info "Sans menu : lsshm status | lsshm doctor | lsshm server status | lsshm key list"
    lsshm_info "Pour installer : curl -fsSL .../lsshm.sh | bash -s -- install"
    exit 1
}

lsshm_tty_restore() {
    stty sane 2>/dev/null || true
}

lsshm_uses_dialog_ui() {
    [ "${LSSHM_UI_MODE:-0}" = "1" ] && lsshm_have dialog
}

# Read one line from stdin or /dev/tty. Sets the named variable on success.
lsshm_read_line() {
    local __var="$1" __prompt="$2" __line=""
    if [ -t 0 ]; then
        IFS= read -r -p "$__prompt" __line || return 1
    elif lsshm_have_tty; then
        IFS= read -r -p "$__prompt" __line </dev/tty || return 1
    else
        return 1
    fi
    printf -v "$__var" '%s' "$__line"
    return 0
}

lsshm_prompt() {
    # lsshm_prompt PROMPT [DEFAULT] -> echoes answer
    local prompt="$1" default="${2:-}" answer="" msg=""
    if ! lsshm_is_interactive; then
        [ -n "$default" ] && { printf '%s' "$default"; return 0; }
        return 1
    fi
    if lsshm_uses_dialog_ui; then
        lsshm_tty_restore
        answer="$(dialog --inputbox "$prompt" 10 70 "$default" 3>&1 1>&2 2>&3)" || answer="$default"
        printf '%s' "${answer:-$default}"
        return 0
    fi
    if [ -n "$default" ]; then
        msg="${prompt} [${default}]: "
    else
        msg="${prompt}: "
    fi
    if lsshm_read_line answer "$msg"; then
        printf '%s' "${answer:-$default}"
    else
        printf '%s' "$default"
    fi
}

lsshm_confirm() {
    # lsshm_confirm PROMPT [default_yes] -> return 0 for yes
    local prompt="$1" default="${2:-no}" answer="" hint="[o/N]"
    if [ "${LSSHM_ASSUME_YES:-0}" = "1" ]; then
        return 0
    fi
    if ! lsshm_is_interactive; then
        [ "$default" = "yes" ]
        return
    fi
    if lsshm_uses_dialog_ui; then
        lsshm_tty_restore
        if dialog --backtitle "$LSSHM_LONG_NAME v$LSSHM_VERSION" \
            --yesno "$prompt" 10 70 3>&1 1>&2 2>&3; then
            return 0
        fi
        return 1
    fi
    [ "$default" = "yes" ] && hint="[O/n]"
    if ! lsshm_read_line answer "${prompt} ${hint} "; then
        [ "$default" = "yes" ]
        return
    fi
    answer="$(printf '%s' "$answer" | tr '[:upper:]' '[:lower:]')"
    case "$answer" in
        o|oui|y|yes) return 0 ;;
        n|non|no)    return 1 ;;
        "")          [ "$default" = "yes" ] ;;
        *)           return 1 ;;
    esac
}

lsshm_pause() {
    if lsshm_uses_dialog_ui; then
        return 0
    fi
    lsshm_is_interactive || return 0
    lsshm_read_line _ "Appuyez sur Entrée pour continuer... " || true
}

# -----------------------------------------------------------------------------
# Temporary files (tracked and cleaned on exit)
# -----------------------------------------------------------------------------
LSSHM_TMPFILES=()

lsshm_mktemp() {
    local tmp
    tmp="$(mktemp "${TMPDIR:-/tmp}/lsshm.XXXXXX")" || lsshm_die "Impossible de créer un fichier temporaire."
    LSSHM_TMPFILES+=("$tmp")
    printf '%s' "$tmp"
}

lsshm_cleanup() {
    local f
    for f in "${LSSHM_TMPFILES[@]:-}"; do
        [ -n "$f" ] && rm -f "$f" 2>/dev/null || true
    done
}

# -----------------------------------------------------------------------------
# Small utilities
# -----------------------------------------------------------------------------
lsshm_have() { command -v "$1" >/dev/null 2>&1; }

lsshm_yesno_label() {
    case "$1" in
        yes|true|on|1) printf 'oui' ;;
        no|false|off|0) printf 'non' ;;
        "") printf 'non défini' ;;
        *) printf '%s' "$1" ;;
    esac
}

# Ensure the runtime directories exist.
lsshm_ensure_dirs() {
    local d
    for d in "$LSSHM_CONFIG_DIR" "$LSSHM_DATA_DIR" "$LSSHM_STATE_DIR" \
             "$LSSHM_CACHE_DIR" "$LSSHM_BACKUP_DIR"; do
        [ -d "$d" ] || mkdir -p "$d" 2>/dev/null || true
    done
}

# ===== src/platform.sh =================================================
# shellcheck shell=bash
# =============================================================================
# platform.sh - detect distribution, package manager, service manager, virt
# =============================================================================

lsshm_detect_platform() {
    LSSHM_OS_ID="unknown"
    LSSHM_OS_NAME="Unknown"
    LSSHM_OS_LIKE=""
    LSSHM_OS_VERSION=""

    if [ -r /etc/os-release ]; then
        # shellcheck disable=SC1091
        . /etc/os-release
        LSSHM_OS_ID="${ID:-unknown}"
        LSSHM_OS_NAME="${PRETTY_NAME:-${NAME:-Unknown}}"
        LSSHM_OS_LIKE="${ID_LIKE:-}"
        LSSHM_OS_VERSION="${VERSION_ID:-}"
    fi

    LSSHM_PKG_MGR="$(lsshm_detect_pkg_mgr)"
    LSSHM_SVC_MGR="$(lsshm_detect_svc_mgr)"
    LSSHM_HAS_SYSTEMD=0
    [ "$LSSHM_SVC_MGR" = "systemd" ] && LSSHM_HAS_SYSTEMD=1

    LSSHM_VIRT="$(lsshm_detect_virt)"
    LSSHM_SSHD_BIN="$(lsshm_detect_sshd_bin)"
    LSSHM_SSH_SERVICE="$(lsshm_detect_ssh_service)"
}

lsshm_detect_pkg_mgr() {
    if lsshm_have apt-get; then printf 'apt'
    elif lsshm_have apk; then printf 'apk'
    elif lsshm_have dnf; then printf 'dnf'
    elif lsshm_have yum; then printf 'yum'
    elif lsshm_have pacman; then printf 'pacman'
    elif lsshm_have zypper; then printf 'zypper'
    else printf 'unknown'
    fi
}

lsshm_detect_svc_mgr() {
    if lsshm_have systemctl && [ -d /run/systemd/system ]; then printf 'systemd'
    elif lsshm_have rc-service; then printf 'openrc'
    elif lsshm_have service; then printf 'sysv'
    else printf 'unknown'
    fi
}

lsshm_detect_virt() {
    if lsshm_have systemd-detect-virt; then
        systemd-detect-virt 2>/dev/null || printf 'none'
    elif [ -f /run/systemd/container ]; then
        cat /run/systemd/container 2>/dev/null || printf 'container'
    elif grep -qa 'container=lxc' /proc/1/environ 2>/dev/null; then
        printf 'lxc'
    else
        printf 'unknown'
    fi
}

lsshm_detect_sshd_bin() {
    local candidate
    for candidate in /usr/sbin/sshd /usr/bin/sshd /sbin/sshd; do
        [ -x "$candidate" ] && { printf '%s' "$candidate"; return 0; }
    done
    if lsshm_have sshd; then
        command -v sshd
        return 0
    fi
    printf ''
}

lsshm_detect_ssh_service() {
    # Debian/Ubuntu use "ssh", most RPM/Arch use "sshd".
    case "$LSSHM_OS_ID" in
        debian|ubuntu|raspbian|linuxmint|pop) printf 'ssh' ;;
        *) printf 'sshd' ;;
    esac
}

lsshm_platform_summary() {
    cat <<EOF
Distribution        : $LSSHM_OS_NAME
Identifiant         : $LSSHM_OS_ID ${LSSHM_OS_VERSION:+($LSSHM_OS_VERSION)}
Gestionnaire paquet : $LSSHM_PKG_MGR
Gestionnaire service: $LSSHM_SVC_MGR
systemd             : $([ "$LSSHM_HAS_SYSTEMD" = 1 ] && echo présent || echo absent)
Virtualisation      : $LSSHM_VIRT
Binaire sshd        : ${LSSHM_SSHD_BIN:-non détecté}
Service SSH         : $LSSHM_SSH_SERVICE
EOF
}

# Is the current distribution supported for full management in this version?
lsshm_platform_is_primary() {
    case "$LSSHM_OS_ID" in
        debian) return 0 ;;
        ubuntu|raspbian|linuxmint|pop) return 0 ;;
        *)
            case " $LSSHM_OS_LIKE " in
                *debian*) return 0 ;;
                *) return 1 ;;
            esac
            ;;
    esac
}

# ===== src/privileges.sh ===============================================
# shellcheck shell=bash
# =============================================================================
# privileges.sh - privilege elevation and calling-user resolution
# =============================================================================

lsshm_init_privileges() {
    LSSHM_EUID="$(id -u)"
    LSSHM_IS_ROOT=0
    [ "$LSSHM_EUID" = "0" ] && LSSHM_IS_ROOT=1

    # The user whose personal SSH files should be managed. When invoked through
    # sudo we must not silently manage root's keys.
    LSSHM_CALLING_USER="${LSSHM_TARGET_USER:-${SUDO_USER:-${USER:-$(id -un)}}}"

    if lsshm_have sudo && [ "$LSSHM_IS_ROOT" = "0" ]; then
        LSSHM_SUDO="sudo"
    else
        LSSHM_SUDO=""
    fi
    # Set after a successful sudo -v / privileged auth in this process.
    LSSHM_SUDO_PRIMED="${LSSHM_SUDO_PRIMED:-0}"
}

# Home directory of a given user.
lsshm_user_home() {
    local user="$1" home
    home="$(getent passwd "$user" 2>/dev/null | cut -d: -f6)"
    if [ -z "$home" ]; then
        if [ "$user" = "${USER:-}" ]; then
            home="$HOME"
        else
            home="/home/$user"
        fi
    fi
    printf '%s' "$home"
}

# The .ssh directory for the managed (calling) user.
lsshm_target_ssh_dir() {
    printf '%s/.ssh' "$(lsshm_user_home "$LSSHM_CALLING_USER")"
}

# True if a non-interactive sudo would succeed (cached credentials).
lsshm_sudo_ready() {
    [ "$LSSHM_IS_ROOT" = "1" ] && return 0
    [ -n "${LSSHM_SUDO:-}" ] || return 1
    sudo -n true >/dev/null 2>&1
}

# Ask for the sudo password at most once per session (when needed).
lsshm_sudo_ensure() {
    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        return 0
    fi
    if [ -z "${LSSHM_SUDO:-}" ]; then
        lsshm_error "Cette opération nécessite les privilèges root, mais sudo est introuvable."
        return 1
    fi
    if lsshm_sudo_ready; then
        LSSHM_SUDO_PRIMED=1
        return 0
    fi
    if ! lsshm_is_interactive || [ ! -t 0 ]; then
        lsshm_error "Authentification sudo requise (session non interactive)."
        return 1
    fi
    lsshm_note "Authentification administrateur (sudo) — une seule fois pour cette session."
    if sudo -v; then
        LSSHM_SUDO_PRIMED=1
        return 0
    fi
    lsshm_error "Échec de l’authentification sudo."
    return 1
}

# Run a command that requires root. Uses sudo only when necessary.
# Authenticates once via lsshm_sudo_ensure, then reuses the sudo ticket.
lsshm_run_privileged() {
    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        "$@"
    elif [ -n "$LSSHM_SUDO" ]; then
        lsshm_sudo_ensure || return 1
        # Do not fall back to an interactive sudo on command failure (that would
        # re-prompt for the password when sshd -t / systemctl simply return 1).
        if lsshm_sudo_ready; then
            sudo -n "$@"
        else
            sudo "$@"
        fi
    else
        lsshm_error "Cette opération nécessite les privilèges root, mais sudo est introuvable."
        return 1
    fi
}

# Run several shell commands under a single sudo (one password prompt max).
# Usage: lsshm_run_privileged_sh 'cmd1 && cmd2'
lsshm_run_privileged_sh() {
    local script="$1"
    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        sh -c "$script"
    elif [ -n "$LSSHM_SUDO" ]; then
        lsshm_sudo_ensure || return 1
        if lsshm_sudo_ready; then
            sudo -n sh -c "$script"
        else
            sudo sh -c "$script"
        fi
    else
        lsshm_error "Cette opération nécessite les privilèges root, mais sudo est introuvable."
        return 1
    fi
}

# True if we can obtain root (already root or sudo available).
lsshm_can_elevate() {
    [ "$LSSHM_IS_ROOT" = "1" ] || [ -n "$LSSHM_SUDO" ]
}

lsshm_require_root() {
    if ! lsshm_can_elevate; then
        lsshm_die "Opération privilégiée impossible: exécutez LSSHM en root ou installez sudo."
    fi
}

# Validate and set the user whose personal SSH files are managed.
lsshm_set_target_user() {
    local user="$1"
    if [ -z "$user" ]; then
        lsshm_error "Nom d’utilisateur vide."
        return 1
    fi
    if ! lsshm_user_exists "$user"; then
        lsshm_error "Utilisateur inconnu : $user"
        return 1
    fi
    LSSHM_CALLING_USER="$user"
    LSSHM_TARGET_USER="$user"
    lsshm_ok "Utilisateur administré : $LSSHM_CALLING_USER ($(lsshm_user_home "$LSSHM_CALLING_USER")/.ssh)"
}

# Ensure ~/.ssh exists with correct ownership for a target user (root admin case).
lsshm_ensure_user_ssh_dir() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local home ssh_dir uid gid
    home="$(lsshm_user_home "$user")"
    ssh_dir="$home/.ssh"
    uid="$(id -u "$user" 2>/dev/null || echo 0)"
    gid="$(id -g "$user" 2>/dev/null || echo 0)"

    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        mkdir -p "$ssh_dir"
        chmod 700 "$ssh_dir"
        chown "$uid:$gid" "$ssh_dir"
    else
        mkdir -p "$ssh_dir" 2>/dev/null || lsshm_run_privileged mkdir -p "$ssh_dir"
        chmod 700 "$ssh_dir" 2>/dev/null || true
    fi
}

# chown paths to a login user when we are root (no-op otherwise).
lsshm_chown_user() {
    local user="$1"
    shift
    [ "$LSSHM_IS_ROOT" = "1" ] || return 0
    [ "$#" -gt 0 ] || return 0
    local uid gid
    uid="$(id -u "$user" 2>/dev/null || echo 0)"
    gid="$(id -g "$user" 2>/dev/null || echo 0)"
    chown "$uid:$gid" "$@"
}

# Interactive picker: numbered login users (+ root), or typed name.
lsshm_pick_target_user() {
    local default="${1:-$LSSHM_CALLING_USER}"
    local -a names=()
    local name uid home i=0

    printf '\nUtilisateurs locaux disponibles :\n' >&2
    while IFS=: read -r name uid home; do
        [ -n "$name" ] || continue
        i=$((i + 1))
        names+=("$name")
        printf '  %d. %-16s uid=%-6s %s\n' "$i" "$name" "$uid" "$home" >&2
    done <<EOF
$(lsshm_users_list)
EOF

    if [ "$i" -eq 0 ]; then
        lsshm_error "Aucun utilisateur local détecté."
        return 1
    fi

    local choice
    choice="$(lsshm_prompt "Utilisateur à administrer (numéro ou nom)" "$default")"
    [ -n "$choice" ] || return 1

    if [[ "$choice" =~ ^[0-9]+$ ]]; then
        if [ "$choice" -lt 1 ] || [ "$choice" -gt "${#names[@]}" ]; then
            lsshm_error "Numéro hors plage (1-${#names[@]})."
            return 1
        fi
        choice="${names[$((choice - 1))]}"
    fi

    lsshm_set_target_user "$choice"
}

# Resolve which user's personal SSH files to manage (keys, access, hosts).
lsshm_resolve_target_user() {
    # Explicit --user always wins.
    if [ -n "${LSSHM_TARGET_USER:-}" ]; then
        if ! lsshm_user_exists "$LSSHM_TARGET_USER"; then
            lsshm_die "Utilisateur inconnu : $LSSHM_TARGET_USER"
        fi
        LSSHM_CALLING_USER="$LSSHM_TARGET_USER"
        return 0
    fi

    # Non-interactive: prefer the original sudo user when present.
    if ! lsshm_is_interactive; then
        if [ "$LSSHM_IS_ROOT" = "1" ] && [ -n "${SUDO_USER:-}" ] && [ "$SUDO_USER" != "root" ]; then
            LSSHM_CALLING_USER="$SUDO_USER"
        fi
        return 0
    fi

    # Interactive root (sudo or direct login): choose the managed user.
    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        if [ -n "${SUDO_USER:-}" ] && [ "$SUDO_USER" != "root" ]; then
            printf '\n%s est exécuté avec sudo.\n' "$LSSHM_NAME"
            printf 'Utilisateur appelant  : %s\n' "$SUDO_USER"
            printf 'Utilisateur privilégié: root\n\n'
            printf 'Les fichiers SSH personnels de quel utilisateur faut-il gérer ?\n'
            printf '  1. %s (recommandé)\n' "$SUDO_USER"
            printf '  2. root\n'
            printf '  3. Choisir un autre utilisateur\n'
            local choice; choice="$(lsshm_prompt 'Choix' '1')"
            case "$choice" in
                2) lsshm_set_target_user "root" || LSSHM_CALLING_USER="root" ;;
                3) lsshm_pick_target_user "$SUDO_USER" || LSSHM_CALLING_USER="$SUDO_USER" ;;
                *) lsshm_set_target_user "$SUDO_USER" || LSSHM_CALLING_USER="$SUDO_USER" ;;
            esac
        else
            # Direct root session (Debian LXC, console root, etc.).
            printf '\n%s est exécuté en root.\n' "$LSSHM_NAME"
            printf 'Vous pouvez administrer le SSH d’un autre utilisateur (clés, accès, hosts).\n\n'
            printf 'Les fichiers SSH personnels de quel utilisateur faut-il gérer ?\n'
            printf '  1. root\n'
            printf '  2. Choisir un autre utilisateur\n'
            local choice; choice="$(lsshm_prompt 'Choix' '2')"
            case "$choice" in
                1) lsshm_set_target_user "root" || true ;;
                *) lsshm_pick_target_user "root" || lsshm_set_target_user "root" || true ;;
            esac
        fi
    fi
}

# ===== src/backup.sh ===================================================
# shellcheck shell=bash
# =============================================================================
# backup.sh - backup and restore of managed SSH files
# =============================================================================
# Backups are stored under $LSSHM_BACKUP_DIR as timestamped tar archives.

lsshm_backup_timestamp() { date '+%Y%m%d-%H%M%S'; }

# Copy a single file into a timestamped backup set, preserving path.
# Usage: lsshm_backup_file /etc/ssh/sshd_config [label]
lsshm_backup_file() {
    local src="$1" label="${2:-file}"
    [ -e "$src" ] || return 0
    lsshm_ensure_dirs
    local stamp; stamp="$(lsshm_backup_timestamp)"
    local dest="$LSSHM_BACKUP_DIR/${stamp}-${label}"
    mkdir -p "$dest" 2>/dev/null || true
    local base; base="$(basename "$src")"
    if [ -r "$src" ]; then
        cp -a "$src" "$dest/$base" 2>/dev/null || \
            lsshm_run_privileged cp -a "$src" "$dest/$base"
    else
        lsshm_run_privileged cp -a "$src" "$dest/$base"
    fi
    printf '%s' "$dest/$base"
    lsshm_log INFO "Backup of $src -> $dest/$base"
}

# Full backup of the SSH server configuration tree.
lsshm_backup_server_config() {
    lsshm_ensure_dirs
    local stamp; stamp="$(lsshm_backup_timestamp)"
    local archive="$LSSHM_BACKUP_DIR/${stamp}-sshd-config.tar.gz"
    local tmp; tmp="$(lsshm_mktemp)"
    {
        [ -f /etc/ssh/sshd_config ] && printf '/etc/ssh/sshd_config\n'
        [ -d /etc/ssh/sshd_config.d ] && printf '/etc/ssh/sshd_config.d\n'
    } >"$tmp"
    if [ ! -s "$tmp" ]; then
        lsshm_warn "Aucune configuration serveur à sauvegarder."
        return 1
    fi
    if lsshm_run_privileged tar -czf "$archive" -T "$tmp" 2>/dev/null; then
        lsshm_ok "Sauvegarde créée : $archive"
        printf '%s' "$archive"
        return 0
    fi
    lsshm_error "Échec de la sauvegarde de la configuration serveur."
    return 1
}

# Backup a user's authorized_keys.
lsshm_backup_authorized_keys() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local home; home="$(lsshm_user_home "$user")"
    lsshm_backup_file "$home/.ssh/authorized_keys" "authkeys-$user"
}

lsshm_backup_list() {
    lsshm_ensure_dirs
    if [ -z "$(ls -A "$LSSHM_BACKUP_DIR" 2>/dev/null)" ]; then
        lsshm_info "Aucune sauvegarde enregistrée."
        return 0
    fi
    lsshm_info "Sauvegardes dans $LSSHM_BACKUP_DIR :"
    local entry
    for entry in "$LSSHM_BACKUP_DIR"/*; do
        [ -e "$entry" ] || continue
        printf '  %s\n' "$(basename "$entry")"
    done
}

# Restore the SSH server configuration from an archive.
lsshm_backup_restore_server() {
    local archive="$1"
    if [ ! -f "$archive" ]; then
        # Allow passing just the basename.
        archive="$LSSHM_BACKUP_DIR/$archive"
    fi
    [ -f "$archive" ] || lsshm_die "Archive introuvable : $1"
    lsshm_warn "Restauration de la configuration serveur depuis : $archive"
    lsshm_confirm "Confirmer la restauration ?" no || { lsshm_info "Annulé."; return 1; }
    if lsshm_run_privileged tar -xzf "$archive" -C / ; then
        lsshm_ok "Configuration restaurée."
        lsshm_server_config_test && lsshm_server_reload
    else
        lsshm_error "Échec de la restauration."
        return 1
    fi
}

lsshm_backup_menu() {
    while true; do
        local choice="" pick_ret=0
        if lsshm_uses_dialog_ui; then
            choice="$(lsshm_dialog_backup_menu)" || pick_ret=$?
            [ "$pick_ret" -ne 0 ] && break
        else
            clear 2>/dev/null || true
            lsshm_header
            printf 'Sauvegarde et restauration\n\n'
            cat <<EOF
  1. Sauvegarder la configuration du serveur SSH
  2. Sauvegarder les clés autorisées (authorized_keys)
  3. Lister les sauvegardes
  4. Restaurer une configuration serveur
  5. Retour
EOF
            choice="$(lsshm_prompt 'Choix' '5')"
        fi
        case "$choice" in
            1) lsshm_ui_run "Sauvegarde serveur SSH" lsshm_backup_server_config ;;
            2) lsshm_ui_run "Sauvegarde authorized_keys" lsshm_backup_authorized_keys "$LSSHM_CALLING_USER" ;;
            3) lsshm_ui_run "Sauvegardes disponibles" lsshm_backup_list ;;
            4)
                if lsshm_uses_dialog_ui; then
                    lsshm_ui_show "Sauvegardes" lsshm_backup_list
                else
                    lsshm_backup_list
                fi
                local a; a="$(lsshm_prompt 'Nom de l’archive à restaurer' '')"
                [ -n "$a" ] && lsshm_backup_restore_server "$a"
                lsshm_uses_dialog_ui || lsshm_pause
                ;;
            5|q|Q) break ;;
            *) lsshm_warn "Choix invalide."; lsshm_uses_dialog_ui || lsshm_pause ;;
        esac
    done
}

# ===== src/server.sh ===================================================
# shellcheck shell=bash
# =============================================================================
# server.sh - OpenSSH server service management
# =============================================================================

lsshm_server_is_installed() {
    [ -n "${LSSHM_SSHD_BIN:-}" ] && [ -x "$LSSHM_SSHD_BIN" ]
}

# --- service actions ---------------------------------------------------------

lsshm_server_action() {
    # lsshm_server_action start|stop|restart|reload|enable|disable
    local action="$1"
    case "$LSSHM_SVC_MGR" in
        systemd)
            lsshm_run_privileged systemctl "$action" "$LSSHM_SSH_SERVICE"
            ;;
        openrc)
            case "$action" in
                enable)  lsshm_run_privileged rc-update add "$LSSHM_SSH_SERVICE" default ;;
                disable) lsshm_run_privileged rc-update del "$LSSHM_SSH_SERVICE" default ;;
                reload)  lsshm_run_privileged rc-service "$LSSHM_SSH_SERVICE" reload \
                             || lsshm_run_privileged rc-service "$LSSHM_SSH_SERVICE" restart ;;
                *)       lsshm_run_privileged rc-service "$LSSHM_SSH_SERVICE" "$action" ;;
            esac
            ;;
        sysv)
            case "$action" in
                enable|disable)
                    lsshm_warn "Activation/désactivation automatique non gérée pour SysV ici."
                    return 1 ;;
                *) lsshm_run_privileged service "$LSSHM_SSH_SERVICE" "$action" ;;
            esac
            ;;
        *)
            lsshm_error "Gestionnaire de service inconnu : impossible d'exécuter '$action'."
            return 1
            ;;
    esac
}

lsshm_server_start()   { lsshm_server_action start   && lsshm_ok "Service SSH démarré."; }
lsshm_server_stop()    { lsshm_server_action stop    && lsshm_ok "Service SSH arrêté."; }
lsshm_server_restart() { lsshm_server_action restart && lsshm_ok "Service SSH redémarré."; }
lsshm_server_enable()  { lsshm_server_action enable  && lsshm_ok "Démarrage automatique activé."; }
lsshm_server_disable() { lsshm_server_action disable && lsshm_ok "Démarrage automatique désactivé."; }

# Reload preferred over restart; validate config first.
lsshm_server_reload() {
    if ! lsshm_server_config_test; then
        lsshm_error "Configuration invalide : rechargement annulé."
        return 1
    fi
    if lsshm_server_action reload; then
        lsshm_server_config_invalidate_cache
        lsshm_ok "Service SSH rechargé."
    else
        return 1
    fi
}

# --- status ------------------------------------------------------------------

lsshm_server_is_active() {
    case "$LSSHM_SVC_MGR" in
        systemd) systemctl is-active --quiet "$LSSHM_SSH_SERVICE" ;;
        openrc)  rc-service "$LSSHM_SSH_SERVICE" status >/dev/null 2>&1 ;;
        sysv)    service "$LSSHM_SSH_SERVICE" status >/dev/null 2>&1 ;;
        *)       lsshm_server_port_listening ;;
    esac
}

lsshm_server_is_enabled() {
    case "$LSSHM_SVC_MGR" in
        systemd) systemctl is-enabled --quiet "$LSSHM_SSH_SERVICE" 2>/dev/null ;;
        openrc)  rc-update show default 2>/dev/null | grep -qw "$LSSHM_SSH_SERVICE" ;;
        *)       return 1 ;;
    esac
}

# Is the configured SSH port actually listening?
lsshm_server_port_listening() {
    local port; port="$(lsshm_server_config_effective_value port)"
    port="${port:-22}"
    if lsshm_have ss; then
        ss -ltn 2>/dev/null | grep -Eq "[:.]${port}[[:space:]]"
    elif lsshm_have netstat; then
        netstat -ltn 2>/dev/null | grep -Eq "[:.]${port}[[:space:]]"
    else
        return 2
    fi
}

lsshm_server_status() {
    if ! lsshm_server_is_installed; then
        lsshm_warn "OpenSSH Server n'est pas installé (binaire sshd introuvable)."
        return 0
    fi
    local active enabled port rootlogin passauth pubkey
    if lsshm_server_is_active; then active="actif"; else active="inactif"; fi
    if lsshm_server_is_enabled; then enabled="oui"; else enabled="non"; fi
    port="$(lsshm_server_config_effective_value port)"; port="${port:-22}"
    rootlogin="$(lsshm_server_config_effective_value permitrootlogin)"
    passauth="$(lsshm_server_config_effective_value passwordauthentication)"
    pubkey="$(lsshm_server_config_effective_value pubkeyauthentication)"

    cat <<EOF
État du serveur SSH : $active
Démarrage auto      : $enabled
Port                : $port
Accès root          : $(lsshm_rootlogin_label "$rootlogin")
Auth. mot de passe  : $(lsshm_yesno_label "$passauth")
Auth. par clé       : $(lsshm_yesno_label "$pubkey")
EOF
}

# --- installation ------------------------------------------------------------

lsshm_server_install() {
    if lsshm_server_is_installed; then
        lsshm_ok "OpenSSH Server est déjà installé : $LSSHM_SSHD_BIN"
        return 0
    fi
    lsshm_info "Installation d'OpenSSH Server..."
    lsshm_require_root
    case "$LSSHM_PKG_MGR" in
        apt)
            lsshm_run_privileged apt-get update && \
            lsshm_run_privileged apt-get install -y openssh-server ;;
        apk)
            lsshm_run_privileged apk add openssh ;;
        dnf)
            lsshm_run_privileged dnf install -y openssh-server ;;
        yum)
            lsshm_run_privileged yum install -y openssh-server ;;
        pacman)
            lsshm_run_privileged pacman -Sy --noconfirm openssh ;;
        zypper)
            lsshm_run_privileged zypper install -y openssh ;;
        *)
            lsshm_error "Gestionnaire de paquets non pris en charge : $LSSHM_PKG_MGR"
            return 1 ;;
    esac
    # Refresh detection.
    LSSHM_SSHD_BIN="$(lsshm_detect_sshd_bin)"
    if lsshm_server_is_installed; then
        lsshm_ok "OpenSSH Server installé."
        lsshm_server_action enable || true
        lsshm_server_action start  || true
    else
        lsshm_error "L'installation semble avoir échoué."
        return 1
    fi
}

lsshm_server_logs() {
    local lines="${1:-40}"
    if [ "$LSSHM_SVC_MGR" = "systemd" ] && lsshm_have journalctl; then
        lsshm_run_privileged journalctl -u "$LSSHM_SSH_SERVICE" -n "$lines" --no-pager
    elif [ -f /var/log/auth.log ]; then
        lsshm_run_privileged tail -n "$lines" /var/log/auth.log
    elif [ -f /var/log/secure ]; then
        lsshm_run_privileged tail -n "$lines" /var/log/secure
    else
        lsshm_warn "Aucune source de journaux SSH détectée."
        return 1
    fi
}

# ===== src/server_config.sh ============================================
# shellcheck shell=bash
# =============================================================================
# server_config.sh - sshd_config parsing, effective values, managed drop-in
# =============================================================================

LSSHM_SSHD_CONFIG="/etc/ssh/sshd_config"
LSSHM_MANAGED_CONF="/etc/ssh/sshd_config.d/00-lsshm.conf"

LSSHM_MANAGED_HEADER="# Managed by LSSHM
# Local SSH Manager
# Manual changes may be overwritten."

# --- validation --------------------------------------------------------------

# sshd -t : validate configuration. Returns non-zero on error.
lsshm_server_config_test() {
    if [ -z "${LSSHM_SSHD_BIN:-}" ]; then
        lsshm_warn "Binaire sshd introuvable : validation impossible."
        return 0
    fi
    local out
    if out="$(lsshm_run_privileged "$LSSHM_SSHD_BIN" -t 2>&1)"; then
        return 0
    fi
    lsshm_error "sshd -t a signalé une erreur :"
    printf '%s\n' "$out" >&2
    return 1
}

# Invalidate the cached sshd -T dump (call after config changes).
lsshm_server_config_invalidate_cache() {
    LSSHM_SSHD_T_CACHE=""
    LSSHM_SSHD_T_CACHED=0
}

# sshd -T : dump the effective configuration (cached).
# Never prompts for a sudo password: uses an existing ticket (sudo -n) or fails
# so the status panel / menu can open without asking for admin credentials.
# Pass "refresh" to force a new privileged dump (may prompt once via sudo -v).
lsshm_server_config_dump() {
    local mode="${1:-}"
    [ -n "${LSSHM_SSHD_BIN:-}" ] || return 1

    if [ "$mode" = "refresh" ]; then
        lsshm_server_config_invalidate_cache
        if [ "$LSSHM_IS_ROOT" != "1" ] && [ -n "${LSSHM_SUDO:-}" ]; then
            lsshm_sudo_ensure || return 1
        fi
    fi

    if [ "${LSSHM_SSHD_T_CACHED:-0}" = "1" ]; then
        printf '%s\n' "$LSSHM_SSHD_T_CACHE"
        return 0
    fi

    local dump=""
    if [ "$LSSHM_IS_ROOT" = "1" ]; then
        dump="$("$LSSHM_SSHD_BIN" -T 2>/dev/null)" || return 1
    elif [ -n "${LSSHM_SUDO:-}" ]; then
        # Read-only: never trigger a password prompt here.
        dump="$(sudo -n "$LSSHM_SSHD_BIN" -T 2>/dev/null)" || return 1
    else
        dump="$("$LSSHM_SSHD_BIN" -T 2>/dev/null)" || return 1
    fi

    LSSHM_SSHD_T_CACHE="$dump"
    LSSHM_SSHD_T_CACHED=1
    printf '%s\n' "$dump"
}

# Effective value of a directive (lowercase key). Falls back to file parsing
# when sshd -T is unavailable (e.g. no sudo credentials yet).
lsshm_server_config_effective_value() {
    local key; key="$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')"
    local dump val
    dump="$(lsshm_server_config_dump)" || dump=""
    if [ -n "$dump" ]; then
        val="$(printf '%s\n' "$dump" | awk -v k="$key" 'tolower($1)==k {sub($1 FS,""); print; exit}')"
        [ -n "$val" ] && { printf '%s' "$val"; return 0; }
    fi
    # Fallback: first matching non-comment line across config + includes.
    lsshm_config_parse_value "$key"
}

# Parse a directive value directly from files (first occurrence wins, like sshd).
lsshm_config_parse_value() {
    local key; key="$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')"
    local files; files="$(lsshm_config_effective_files)"
    local f val=""
    while IFS= read -r f; do
        [ -r "$f" ] || continue
        val="$(awk -v k="$key" '
            { line=$0; sub(/#.*/,"",line);
              n=split(line,a," ");
              if (n>=2 && tolower(a[1])==k) { $1=""; sub(/^ /,""); print; exit } }' "$f")"
        [ -n "$val" ] && { printf '%s' "$val"; return 0; }
    done <<EOF
$files
EOF
    printf ''
}

# Ordered list of configuration files: main file, then Include targets in
# lexical order (a simplified model of OpenSSH include handling).
lsshm_config_effective_files() {
    [ -r "$LSSHM_SSHD_CONFIG" ] || { printf '%s\n' "$LSSHM_SSHD_CONFIG"; return; }
    local line trimmed keyword rest pattern g
    # Emit files in the order they are referenced in the main file, expanding
    # Include directives at the point where they appear. Uses bash string
    # operations only (no per-line subprocess) so it stays fast on any host.
    while IFS= read -r line; do
        trimmed="${line#"${line%%[![:space:]]*}"}"
        keyword="${trimmed%%[[:space:]]*}"
        case "$keyword" in
            [Ii]nclude)
                rest="${trimmed#"$keyword"}"
                rest="${rest#"${rest%%[![:space:]]*}"}"
                for pattern in $rest; do
                    case "$pattern" in
                        /*) : ;;
                        *) pattern="/etc/ssh/$pattern" ;;
                    esac
                    for g in $pattern; do
                        [ -f "$g" ] && printf '%s\n' "$g"
                    done
                done
                ;;
        esac
    done <"$LSSHM_SSHD_CONFIG"
    # The main file itself participates too (directives outside includes).
    printf '%s\n' "$LSSHM_SSHD_CONFIG"
}

# Detect whether the main config defines a directive BEFORE its Include line.
# Such an early definition would win over the managed drop-in.
lsshm_config_defined_before_include() {
    local key; key="$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')"
    [ -r "$LSSHM_SSHD_CONFIG" ] || return 1
    awk -v k="$key" '
        BEGIN{seen=0; inc=0}
        {
            line=$0; sub(/#.*/,"",line);
            n=split(line,a," ");
            if (n>=1 && tolower(a[1])=="include") { inc=1 }
            if (!inc && n>=2 && tolower(a[1])==k) { seen=1 }
        }
        END{ exit (seen?0:1) }
    ' "$LSSHM_SSHD_CONFIG"
}

# --- managed drop-in ---------------------------------------------------------

lsshm_managed_ensure_include() {
    # Warn if the main config has no Include for sshd_config.d.
    [ -r "$LSSHM_SSHD_CONFIG" ] || return 0
    if ! grep -Eqi '^[[:space:]]*Include[[:space:]]+.*sshd_config\.d' "$LSSHM_SSHD_CONFIG"; then
        lsshm_warn "Le fichier principal n'inclut pas sshd_config.d/."
        lsshm_warn "Le fichier géré par LSSHM pourrait être ignoré."
    fi
}

# Read current value from the managed file only.
lsshm_managed_get() {
    local key; key="$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')"
    local awk_prog='{ n=split($0,a," "); if (n>=2 && tolower(a[1])==k){ $1=""; sub(/^ /,""); print; exit } }'
    if [ -r "$LSSHM_MANAGED_CONF" ]; then
        awk -v k="$key" "$awk_prog" "$LSSHM_MANAGED_CONF" 2>/dev/null
        return 0
    fi
    [ -e "$LSSHM_MANAGED_CONF" ] || return 1
    lsshm_run_privileged awk -v k="$key" "$awk_prog" "$LSSHM_MANAGED_CONF" 2>/dev/null
}

# Upsert a directive into the managed drop-in file and validate.
# Usage: lsshm_managed_set KEY VALUE
lsshm_managed_set() {
    local key="$1" value="$2"
    lsshm_require_root
    lsshm_managed_ensure_include

    if lsshm_config_defined_before_include "$key"; then
        lsshm_warn "'$key' est défini dans $LSSHM_SSHD_CONFIG avant l'Include."
        lsshm_warn "Cette valeur prévaudra sur le fichier géré par LSSHM."
        if lsshm_confirm "Commenter cette définition dans le fichier principal ?" no; then
            lsshm_config_comment_directive "$key"
        fi
    fi

    local tmp; tmp="$(lsshm_mktemp)"
    # Start from existing managed file or a fresh header (one sudo for the read).
    if [ -r "$LSSHM_MANAGED_CONF" ]; then
        cat "$LSSHM_MANAGED_CONF" >"$tmp" 2>/dev/null || true
    elif [ -e "$LSSHM_MANAGED_CONF" ]; then
        lsshm_run_privileged cat "$LSSHM_MANAGED_CONF" >"$tmp" 2>/dev/null || true
    fi
    if [ ! -s "$tmp" ]; then
        printf '%s\n\n' "$LSSHM_MANAGED_HEADER" >"$tmp"
    fi

    # Remove any existing line for this key, then append the new value.
    local tmp2; tmp2="$(lsshm_mktemp)"
    awk -v k="$key" '
        { n=split($0,a," "); if (n>=1 && tolower(a[1])==tolower(k)) next; print }
    ' "$tmp" >"$tmp2"
    printf '%s %s\n' "$key" "$value" >>"$tmp2"

    # Install atomically with correct permissions, then validate.
    lsshm_backup_file "$LSSHM_MANAGED_CONF" "managed-conf" >/dev/null 2>&1 || true
    lsshm_run_privileged install -m 0644 -o root -g root "$tmp2" "$LSSHM_MANAGED_CONF"
    lsshm_server_config_invalidate_cache

    if ! lsshm_server_config_test; then
        lsshm_error "Nouvelle configuration invalide : annulation."
        lsshm_run_privileged install -m 0644 "$tmp" "$LSSHM_MANAGED_CONF" 2>/dev/null || true
        lsshm_server_config_invalidate_cache
        return 1
    fi
    lsshm_ok "Directive appliquée : $key $value"

    # Confirm the effective runtime value matches the intended choice.
    local eff_key eff_val norm_eff norm_want
    eff_key="$(printf '%s' "$key" | tr '[:upper:]' '[:lower:]')"
    # Prefer a fresh privileged dump when credentials are already warm.
    lsshm_server_config_dump >/dev/null 2>&1 || true
    eff_val="$(lsshm_server_config_effective_value "$eff_key")"
    if [ -n "$eff_val" ]; then
        norm_eff="$(printf '%s' "$eff_val" | tr '[:upper:]' '[:lower:]')"
        norm_want="$(printf '%s' "$value" | tr '[:upper:]' '[:lower:]')"
        case "$eff_key" in
            permitrootlogin)
                [ "$norm_eff" = "without-password" ] && norm_eff="prohibit-password"
                ;;
        esac
        if [ "$norm_eff" != "$norm_want" ]; then
            lsshm_warn "Valeur effective (sshd -T) : $eff_val"
            lsshm_warn "Attendu : $value - une autre définition peut encore prévaloir."
        fi
    fi
    return 0
}

# Comment out a directive in the main config (with backup).
lsshm_config_comment_directive() {
    local key="$1"
    lsshm_backup_file "$LSSHM_SSHD_CONFIG" "main-config" >/dev/null 2>&1 || true
    local tmp; tmp="$(lsshm_mktemp)"
    lsshm_run_privileged awk -v k="$key" '
        { n=split($0,a," ");
          if (n>=2 && tolower(a[1])==tolower(k) && a[1] !~ /^#/)
              print "# LSSHM disabled: " $0;
          else print }
    ' "$LSSHM_SSHD_CONFIG" >"$tmp"
    lsshm_run_privileged install -m 0644 "$tmp" "$LSSHM_SSHD_CONFIG"
}

# --- human-readable directives ----------------------------------------------

lsshm_rootlogin_label() {
    case "$1" in
        no)                   printf 'interdit' ;;
        prohibit-password|without-password) printf 'clé uniquement' ;;
        yes)                  printf 'clé ou mot de passe' ;;
        forced-commands-only) printf 'commandes imposées' ;;
        "")                   printf 'non défini' ;;
        *)                    printf '%s' "$1" ;;
    esac
}

lsshm_set_root_login() {
    lsshm_header
    printf 'Connexion SSH de root\n\n'
    printf '  1. Interdire totalement root\n'
    printf '  2. Autoriser root uniquement avec une clé\n'
    printf '  3. Autoriser root avec une clé ou un mot de passe\n'
    printf '  4. Autoriser root uniquement pour des commandes imposées\n\n'
    printf 'Recommandation : autoriser root uniquement avec une clé,\n'
    printf 'ou utiliser un utilisateur normal possédant sudo.\n\n'
    local choice; choice="$(lsshm_prompt 'Choix' '2')"
    local value=""
    case "$choice" in
        1) value="no" ;;
        2) value="prohibit-password" ;;
        3) value="yes" ;;
        4) value="forced-commands-only" ;;
        *) lsshm_info "Aucun changement."; return 0 ;;
    esac
    lsshm_apply_dangerous_change "PermitRootLogin" "$value" "modification de l'accès root"
}

lsshm_set_password_auth() {
    local cur; cur="$(lsshm_server_config_effective_value passwordauthentication)"
    lsshm_info "Authentification par mot de passe actuelle : $(lsshm_yesno_label "$cur")"
    if lsshm_confirm "Autoriser l'authentification par mot de passe ?" no; then
        lsshm_managed_set "PasswordAuthentication" "yes" && lsshm_server_reload
    else
        lsshm_warn "Désactiver les mots de passe peut vous verrouiller sans clé valide."
        lsshm_apply_dangerous_change "PasswordAuthentication" "no" "désactivation des mots de passe"
    fi
}

lsshm_set_pubkey_auth() {
    if lsshm_confirm "Autoriser l'authentification par clé publique ?" yes; then
        lsshm_managed_set "PubkeyAuthentication" "yes" && lsshm_server_reload
    else
        lsshm_warn "Désactiver l'authentification par clé peut vous verrouiller."
        lsshm_apply_dangerous_change "PubkeyAuthentication" "no" "désactivation de l'authentification par clé"
    fi
}

lsshm_set_port() {
    local cur; cur="$(lsshm_server_config_effective_value port)"; cur="${cur:-22}"
    local port; port="$(lsshm_prompt 'Nouveau port SSH' "$cur")"
    case "$port" in
        ''|*[!0-9]*) lsshm_error "Port invalide."; return 1 ;;
    esac
    if [ "$port" -lt 1 ] || [ "$port" -gt 65535 ]; then
        lsshm_error "Port hors plage (1-65535)."; return 1
    fi
    lsshm_warn "Vérifiez votre pare-feu avant de changer le port."
    lsshm_apply_dangerous_change "Port" "$port" "changement du port"
}

lsshm_set_allow_users() {
    local cur; cur="$(lsshm_server_config_effective_value allowusers)"
    lsshm_info "AllowUsers actuel : ${cur:-non défini}"
    local users; users="$(lsshm_prompt 'Utilisateurs autorisés (séparés par des espaces, vide = supprimer)' "$cur")"
    if [ -z "$users" ]; then
        lsshm_info "Suppression de AllowUsers non gérée automatiquement (éditez le fichier géré)."
        return 0
    fi
    lsshm_apply_dangerous_change "AllowUsers" "$users" "modification de AllowUsers"
}

lsshm_set_allow_groups() {
    local cur; cur="$(lsshm_server_config_effective_value allowgroups)"
    lsshm_info "AllowGroups actuel : ${cur:-non défini}"
    local groups; groups="$(lsshm_prompt 'Groupes autorisés (séparés par des espaces)' "$cur")"
    [ -z "$groups" ] && { lsshm_info "Aucun changement."; return 0; }
    lsshm_apply_dangerous_change "AllowGroups" "$groups" "modification de AllowGroups"
}

# Show the effective configuration (sshd -T) or a helpful message.
lsshm_server_config_show() {
    local dump
    # Explicit request: allow one sudo prompt to get the real effective dump.
    dump="$(lsshm_server_config_dump refresh)" || dump="$(lsshm_server_config_dump)" || dump=""
    if [ -n "$dump" ]; then
        printf '%s\n' "$dump" | sort
    else
        lsshm_warn "sshd -T indisponible. Fichiers de configuration détectés :"
        lsshm_config_effective_files
    fi
}

# ===== src/rollback.sh =================================================
# shellcheck shell=bash
# =============================================================================
# rollback.sh - safe application of dangerous changes with automatic rollback
# =============================================================================
# Dangerous changes (port, disabling passwords, root access, AllowUsers,
# PubkeyAuthentication, ListenAddress) can lock a remote administrator out.
# LSSHM therefore:
#   1. backs up the configuration
#   2. schedules an automatic restore
#   3. applies the change and reloads SSH
#   4. verifies the port is listening
#   5. asks for confirmation from a second session (never auto-kept via -y)
#   6. cancels the automatic restore only after confirmation

LSSHM_ROLLBACK_UNIT="lsshm-rollback"
LSSHM_ROLLBACK_DELAY="${LSSHM_ROLLBACK_DELAY:-120}"

# True when a controlling TTY is available (ignores LSSHM_ASSUME_YES).
lsshm_can_prompt_tty() {
    [ -t 0 ] && [ -t 1 ] && return 0
    lsshm_have_tty && return 0
    return 1
}

# Prompt that always reads the TTY; never auto-answered by -y.
# Used for the post-change rollback confirmation.
lsshm_prompt_tty() {
    local prompt="$1" default="${2:-}" answer="" msg=""
    if [ -n "$default" ]; then
        msg="${prompt} [${default}]: "
    else
        msg="${prompt}: "
    fi
    if ! lsshm_read_line answer "$msg"; then
        printf '%s' "$default"
        return 0
    fi
    printf '%s' "${answer:-$default}"
}

# Build a self-contained restore script that reverts to a backup archive.
lsshm_rollback_build_script() {
    local archive="$1" confirm_flag="$2" delay="$3"
    local script; script="$(lsshm_mktemp)"
    cat >"$script" <<EOF
#!/bin/sh
# LSSHM automatic rollback helper
sleep "$delay"
if [ -f "$confirm_flag" ]; then
    rm -f "$confirm_flag"
    exit 0
fi
tar -xzf "$archive" -C / 2>/dev/null
if command -v systemctl >/dev/null 2>&1; then
    systemctl reload "$LSSHM_SSH_SERVICE" 2>/dev/null || systemctl restart "$LSSHM_SSH_SERVICE" 2>/dev/null
elif command -v rc-service >/dev/null 2>&1; then
    rc-service "$LSSHM_SSH_SERVICE" restart 2>/dev/null
else
    service "$LSSHM_SSH_SERVICE" restart 2>/dev/null
fi
EOF
    chmod +x "$script"
    printf '%s' "$script"
}

lsshm_rollback_schedule() {
    # lsshm_rollback_schedule SCRIPT DELAY -> echoes cancel token
    local script="$1" delay="$2"
    if [ "$LSSHM_HAS_SYSTEMD" = "1" ] && lsshm_have systemd-run; then
        lsshm_run_privileged systemd-run --unit="$LSSHM_ROLLBACK_UNIT" \
            --description="LSSHM automatic SSH rollback" \
            /bin/sh "$script" >/dev/null 2>&1 && { printf 'systemd'; return 0; }
    fi
    # Fallback: detached nohup process. Cancellation relies on the confirm flag.
    lsshm_run_privileged sh -c "nohup /bin/sh '$script' >/dev/null 2>&1 &"
    printf 'nohup'
}

lsshm_rollback_cancel() {
    local method="$1" confirm_flag="$2"
    # The confirm flag stops both methods when the helper wakes up.
    lsshm_run_privileged touch "$confirm_flag" 2>/dev/null || true
    if [ "$method" = "systemd" ] && lsshm_have systemctl; then
        lsshm_run_privileged systemctl stop "$LSSHM_ROLLBACK_UNIT" 2>/dev/null || true
        lsshm_run_privileged systemctl reset-failed "$LSSHM_ROLLBACK_UNIT" 2>/dev/null || true
    fi
}

# Main entry used by server_config.sh for dangerous directives.
lsshm_apply_dangerous_change() {
    local key="$1" value="$2" description="$3"

    # Dangerous changes require a TTY so the operator can confirm from a second session.
    # -y may auto-confirm the initial consent, but never skips the rollback safety net.
    if ! lsshm_can_prompt_tty; then
        lsshm_error "Changement sensible impossible sans terminal interactif : $description"
        lsshm_info "Un TTY est requis pour confirmer que la nouvelle session SSH fonctionne."
        return 1
    fi

    lsshm_warn "Changement sensible : $description"
    if ! lsshm_confirm "Continuer avec une restauration automatique de sécurité ?" no; then
        lsshm_info "Annulé."
        return 1
    fi

    # 1. Backup.
    local archive; archive="$(lsshm_backup_server_config)" || return 1

    # 2. Apply the change (validates internally).
    if ! lsshm_managed_set "$key" "$value"; then
        lsshm_error "Application annulée."
        return 1
    fi

    # 3. Always schedule automatic restore (never skip under -y).
    local confirm_flag="$LSSHM_STATE_DIR/rollback.confirm"
    lsshm_run_privileged rm -f "$confirm_flag" 2>/dev/null || true
    local script; script="$(lsshm_rollback_build_script "$archive" "$confirm_flag" "$LSSHM_ROLLBACK_DELAY")"
    local method; method="$(lsshm_rollback_schedule "$script" "$LSSHM_ROLLBACK_DELAY")"

    # 4. Reload SSH.
    lsshm_server_reload || true

    # 5. Verify the port listens.
    if lsshm_server_port_listening; then
        lsshm_ok "Le port SSH écoute."
    else
        lsshm_warn "Impossible de confirmer que le port SSH écoute."
    fi

    # 6. Ask for confirmation from a second session (never auto-kept via -y).
    cat <<EOF

La nouvelle configuration est active.

Une restauration automatique aura lieu dans ${LSSHM_ROLLBACK_DELAY} secondes.

Ouvrez une seconde connexion SSH avant de confirmer.

  1. La nouvelle connexion fonctionne
  2. Restaurer immédiatement
EOF
    local choice; choice="$(lsshm_prompt_tty 'Choix' '2')"
    case "$choice" in
        1)
            lsshm_rollback_cancel "$method" "$confirm_flag"
            lsshm_ok "Restauration automatique annulée. Changement conservé."
            ;;
        *)
            lsshm_warn "Restauration immédiate..."
            lsshm_run_privileged tar -xzf "$archive" -C / 2>/dev/null || true
            lsshm_rollback_cancel "$method" "$confirm_flag"
            lsshm_server_reload || true
            lsshm_ok "Configuration précédente restaurée."
            ;;
    esac
}

# ===== src/users.sh ====================================================
# shellcheck shell=bash
# =============================================================================
# users.sh - local user helpers
# =============================================================================

# List human/login users (UID >= 1000) plus root.
lsshm_users_list() {
    if lsshm_have getent; then
        getent passwd | awk -F: '($3==0)||($3>=1000 && $3<65534){print $1":"$3":"$6}'
    else
        awk -F: '($3==0)||($3>=1000 && $3<65534){print $1":"$3":"$6}' /etc/passwd
    fi
}

lsshm_users_print() {
    lsshm_info "Utilisateurs locaux :"
    local name uid home
    while IFS=: read -r name uid home; do
        printf '  %-16s uid=%-6s %s\n' "$name" "$uid" "$home"
    done <<EOF
$(lsshm_users_list)
EOF
}

lsshm_user_exists() {
    if lsshm_have getent; then
        getent passwd "$1" >/dev/null 2>&1
    else
        grep -q "^$1:" /etc/passwd 2>/dev/null
    fi
}

# Count authorized keys for a user. Quiet: returns 0 when unreadable without
# attempting privilege elevation (used in the status panel).
lsshm_user_key_count() {
    local user="$1" home ak count
    home="$(lsshm_user_home "$user")"
    ak="$home/.ssh/authorized_keys"
    if [ -r "$ak" ]; then
        count="$(grep -Ecv '^[[:space:]]*($|#)' "$ak" 2>/dev/null)"
        printf '%s' "${count:-0}"
    else
        printf '0'
    fi
}

# ===== src/authorized_keys.sh ==========================================
# shellcheck shell=bash
# =============================================================================
# authorized_keys.sh - incoming access: keys allowed to reach THIS machine
# =============================================================================
# This manages ~/.ssh/authorized_keys for a given user. These are the public
# keys that are ALLOWED TO CONNECT to this machine.

lsshm_access_file() {
    local user="${1:-$LSSHM_CALLING_USER}"
    printf '%s/.ssh/authorized_keys' "$(lsshm_user_home "$user")"
}

# Read the authorized_keys file (with privileges if needed).
lsshm_access_read() {
    local file="$1"
    if [ -r "$file" ]; then
        cat "$file"
    elif lsshm_can_elevate; then
        lsshm_run_privileged cat "$file" 2>/dev/null
    fi
}

# Compute the SHA256 fingerprint and type of a single key line.
lsshm_access_fingerprint_line() {
    local line="$1" tmp out
    tmp="$(lsshm_mktemp)"
    printf '%s\n' "$line" >"$tmp"
    out="$(ssh-keygen -lf "$tmp" 2>/dev/null)" || { printf ''; return 1; }
    printf '%s' "$out"
}

# Classify a line from authorized_keys for shared indexing.
# Sets: _ak_kind (active|disabled|skip), _ak_keyline (raw key line to fingerprint).
lsshm_access_classify_line() {
    local line="$1"
    _ak_kind="skip"
    _ak_keyline=""
    case "$line" in
        '# LSSHM-DISABLED '*)
            _ak_kind="disabled"
            _ak_keyline="${line#\# LSSHM-DISABLED }"
            ;;
        ''|'#'*)
            _ak_kind="skip"
            ;;
        *)
            _ak_kind="active"
            _ak_keyline="$line"
            ;;
    esac
}

# List authorized keys for a user with details.
# Indexing includes both active and LSSHM-DISABLED entries (same as remove/disable).
lsshm_access_list() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local file; file="$(lsshm_access_file "$user")"
    printf 'Utilisateur : %s\n' "$user"
    printf 'Fichier     : %s\n\n' "$file"

    local content; content="$(lsshm_access_read "$file")"
    if [ -z "$content" ]; then
        lsshm_info "Aucune clé autorisée."
        return 0
    fi

    local i=0 line fp bits type comment info
    while IFS= read -r line; do
        lsshm_access_classify_line "$line"
        [ "$_ak_kind" = "skip" ] && continue
        i=$((i+1))
        info="$(lsshm_access_fingerprint_line "$_ak_keyline")"
        bits="$(printf '%s' "$info" | awk '{print $1}')"
        fp="$(printf '%s' "$info" | awk '{print $2}')"
        type="$(printf '%s' "$info" | awk '{print $NF}' | tr -d '()')"
        comment="$(printf '%s' "$_ak_keyline" | awk '{ for(i=3;i<=NF;i++) printf "%s%s", $i, (i<NF?" ":"") }')"
        if [ "$_ak_kind" = "disabled" ]; then
            printf '%d. [DÉSACTIVÉE] %s\n' "$i" "${comment:-sans commentaire}"
        else
            printf '%d. %s\n' "$i" "${comment:-sans commentaire}"
        fi
        printf '   Type       : %s (%s bits)\n' "${type:-?}" "${bits:-?}"
        printf '   Empreinte  : %s\n' "${fp:-inconnue}"
        case "$_ak_keyline" in
            *from=*)       printf '   Restriction : %s\n' "$(printf '%s' "$_ak_keyline" | grep -o 'from="[^"]*"')" ;;
        esac
        case "$_ak_keyline" in
            *command=*)    printf '   Commande    : %s\n' "$(printf '%s' "$_ak_keyline" | grep -o 'command="[^"]*"')" ;;
        esac
        case "$_ak_keyline" in
            *no-port-forwarding*) printf '   Transfert  : interdit\n' ;;
        esac
    done <<EOF
$content
EOF
}

# Write new content to the authorized_keys file with correct ownership/perms.
lsshm_access_write() {
    local user="$1" file="$2" tmp="$3"
    local home; home="$(lsshm_user_home "$user")"
    local ssh_dir="$home/.ssh"
    local uid gid
    uid="$(id -u "$user" 2>/dev/null || echo 0)"
    gid="$(id -g "$user" 2>/dev/null || echo 0)"

    if [ -w "$ssh_dir" ] || { [ ! -e "$ssh_dir" ] && [ -w "$home" ]; }; then
        mkdir -p "$ssh_dir"
        install -m 0600 "$tmp" "$file"
        chmod 700 "$ssh_dir"
    else
        lsshm_run_privileged mkdir -p "$ssh_dir"
        lsshm_run_privileged install -m 0600 -o "$uid" -g "$gid" "$tmp" "$file"
        lsshm_run_privileged chmod 700 "$ssh_dir"
        lsshm_run_privileged chown "$uid:$gid" "$ssh_dir"
    fi
}

# Add a public key (pasted or from a .pub file).
lsshm_access_add() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local keyline="${2:-}"
    if [ -z "$keyline" ]; then
        if lsshm_is_interactive; then
            printf 'Collez la clé publique (une ligne), puis Entrée :\n'
            read -r keyline </dev/tty || keyline=""
        fi
    fi
    # Support importing from a file path.
    if [ -f "$keyline" ]; then
        keyline="$(cat "$keyline")"
    fi
    [ -n "$keyline" ] || { lsshm_error "Aucune clé fournie."; return 1; }

    # Validate that it parses as a key.
    if ! lsshm_access_fingerprint_line "$keyline" >/dev/null; then
        lsshm_error "La clé fournie n'est pas une clé publique valide."
        return 1
    fi

    local file; file="$(lsshm_access_file "$user")"
    lsshm_backup_authorized_keys "$user" >/dev/null 2>&1 || true
    local tmp; tmp="$(lsshm_mktemp)"
    lsshm_access_read "$file" >"$tmp" 2>/dev/null || true

    # Duplicate detection by fingerprint.
    local newfp; newfp="$(lsshm_access_fingerprint_line "$keyline" | awk '{print $2}')"
    local existing
    while IFS= read -r existing; do
        case "$existing" in ''|'#'*) continue ;; esac
        local efp; efp="$(lsshm_access_fingerprint_line "$existing" | awk '{print $2}')"
        if [ -n "$efp" ] && [ "$efp" = "$newfp" ]; then
            lsshm_warn "Cette clé est déjà autorisée (empreinte $efp)."
            return 0
        fi
    done <"$tmp"

    printf '%s\n' "$keyline" >>"$tmp"
    lsshm_access_write "$user" "$file" "$tmp"
    lsshm_ok "Clé ajoutée pour $user."
}

# Remove a key by fingerprint or by 1-based index (same numbering as list).
lsshm_access_remove() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local target="${2:-}"
    local file; file="$(lsshm_access_file "$user")"
    local content; content="$(lsshm_access_read "$file")"
    [ -n "$content" ] || { lsshm_info "Aucune clé à supprimer."; return 0; }

    if [ -z "$target" ]; then
        lsshm_access_list "$user"
        target="$(lsshm_prompt 'Empreinte SHA256 ou numéro à supprimer' '')"
    fi
    [ -n "$target" ] || { lsshm_info "Annulé."; return 0; }

    lsshm_backup_authorized_keys "$user" >/dev/null 2>&1 || true
    local tmp; tmp="$(lsshm_mktemp)"
    local i=0 removed=0 line fp
    while IFS= read -r line; do
        lsshm_access_classify_line "$line"
        if [ "$_ak_kind" = "skip" ]; then
            printf '%s\n' "$line" >>"$tmp"
            continue
        fi
        i=$((i+1))
        fp="$(lsshm_access_fingerprint_line "$_ak_keyline" | awk '{print $2}')"
        if [ "$target" = "$i" ] || { [ -n "$fp" ] && [ "$target" = "$fp" ]; }; then
            removed=1
            continue
        fi
        printf '%s\n' "$line" >>"$tmp"
    done <<EOF
$content
EOF
    if [ "$removed" = "0" ]; then
        lsshm_warn "Aucune clé correspondante trouvée."
        return 1
    fi
    lsshm_access_write "$user" "$file" "$tmp"
    lsshm_ok "Clé supprimée pour $user."
}

# Repair ownership and permissions of the user's .ssh directory.
lsshm_access_repair() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local home; home="$(lsshm_user_home "$user")"
    local ssh_dir="$home/.ssh"
    local uid gid
    uid="$(id -u "$user" 2>/dev/null || echo 0)"
    gid="$(id -g "$user" 2>/dev/null || echo 0)"

    [ -d "$ssh_dir" ] || { lsshm_warn "$ssh_dir n'existe pas."; return 0; }

    local runner=""
    [ -w "$ssh_dir" ] || runner="lsshm_run_privileged"

    $runner chown -R "$uid:$gid" "$ssh_dir"
    $runner chmod 700 "$ssh_dir"
    [ -e "$ssh_dir/authorized_keys" ] && $runner chmod 600 "$ssh_dir/authorized_keys"
    local f
    for f in "$ssh_dir"/id_* "$ssh_dir"/*.pub; do
        [ -e "$f" ] || continue
        case "$f" in
            *.pub) $runner chmod 644 "$f" ;;
            *)     $runner chmod 600 "$f" ;;
        esac
    done
    lsshm_ok "Permissions réparées pour $user :"
    lsshm_info "  .ssh 700, authorized_keys 600, clés privées 600, clés publiques 644"
}

# Temporarily disable or re-enable a key by fingerprint or index (same numbering as list).
lsshm_access_disable() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local target="${2:-}"
    local file; file="$(lsshm_access_file "$user")"
    local content; content="$(lsshm_access_read "$file")"
    [ -n "$content" ] || { lsshm_info "Aucune clé à désactiver."; return 0; }

    if [ -z "$target" ]; then
        lsshm_access_list "$user"
        target="$(lsshm_prompt 'Empreinte SHA256 ou numéro à désactiver/réactiver' '')"
    fi
    [ -n "$target" ] || { lsshm_info "Annulé."; return 0; }

    lsshm_backup_authorized_keys "$user" >/dev/null 2>&1 || true
    local tmp; tmp="$(lsshm_mktemp)"
    local i=0 changed=0 line fp
    while IFS= read -r line; do
        lsshm_access_classify_line "$line"
        if [ "$_ak_kind" = "skip" ]; then
            printf '%s\n' "$line" >>"$tmp"
            continue
        fi
        i=$((i+1))
        fp="$(lsshm_access_fingerprint_line "$_ak_keyline" | awk '{print $2}')"
        if [ "$target" = "$i" ] || { [ -n "$fp" ] && [ "$target" = "$fp" ]; }; then
            if [ "$_ak_kind" = "disabled" ]; then
                printf '%s\n' "$_ak_keyline" >>"$tmp"
            else
                printf '# LSSHM-DISABLED %s\n' "$line" >>"$tmp"
            fi
            changed=1
        else
            printf '%s\n' "$line" >>"$tmp"
        fi
    done <<EOF
$content
EOF
    if [ "$changed" = "0" ]; then
        lsshm_warn "Aucune clé correspondante trouvée."
        return 1
    fi
    lsshm_access_write "$user" "$file" "$tmp"
    lsshm_ok "État de la clé mis à jour pour $user."
}

# Detect duplicate keys across the file.
lsshm_access_duplicates() {
    local user="${1:-$LSSHM_CALLING_USER}"
    local file; file="$(lsshm_access_file "$user")"
    local content; content="$(lsshm_access_read "$file")"
    [ -n "$content" ] || { lsshm_info "Aucune clé."; return 0; }
    local line fp
    printf '%s\n' "$content" | while IFS= read -r line; do
        case "$line" in ''|'#'*) continue ;; esac
        lsshm_access_fingerprint_line "$line" | awk '{print $2}'
    done | sort | uniq -d | while IFS= read -r fp; do
        [ -n "$fp" ] && lsshm_warn "Doublon détecté : $fp"
    done
    lsshm_ok "Analyse des doublons terminée."
}

# ===== src/local_keys.sh ===============================================
# shellcheck shell=bash
# =============================================================================
# local_keys.sh - keys used by THIS machine to connect ELSEWHERE
# =============================================================================
# These are private/public key pairs in ~/.ssh/id_* used for outgoing SSH
# connections. LSSHM must never transmit or display a private key without an
# explicit warning.

lsshm_keys_dir() {
    lsshm_target_ssh_dir
}

# Fill LSSHM_KEY_PATHS with private-key paths (one per .pub found).
# Returns the count via stdout when used as: count="$(lsshm_keys_collect)"
lsshm_keys_collect() {
    LSSHM_KEY_PATHS=()
    local dir; dir="$(lsshm_keys_dir)"
    [ -d "$dir" ] || { printf '0'; return 0; }
    local pub priv
    for pub in "$dir"/*.pub; do
        [ -e "$pub" ] || continue
        priv="${pub%.pub}"
        LSSHM_KEY_PATHS+=("$priv")
    done
    printf '%s' "${#LSSHM_KEY_PATHS[@]}"
}

# Print a numbered list of key pairs (same numbering as pick).
lsshm_keys_print_numbered() {
    local dir; dir="$(lsshm_keys_dir)"
    printf 'Répertoire : %s\n\n' "$dir"
    local count; count="$(lsshm_keys_collect)"
    if [ "$count" = "0" ]; then
        lsshm_info "Aucune paire de clés détectée."
        return 1
    fi
    local i=0 priv pub info
    for priv in "${LSSHM_KEY_PATHS[@]}"; do
        i=$((i+1))
        pub="$priv.pub"
        info="$(ssh-keygen -lf "$pub" 2>/dev/null)"
        printf '%d. %s\n' "$i" "$(basename "$priv")"
        printf '   Clé publique : %s\n' "$pub"
        printf '   Clé privée   : %s\n' "$([ -f "$priv" ] && echo "$priv (présente)" || echo "absente")"
        printf '   Empreinte    : %s\n' "${info:-inconnue}"
    done
    return 0
}

# Detect existing key pairs (files with a matching .pub).
lsshm_keys_list() {
    lsshm_keys_print_numbered || true
}

# Interactive picker: list keys, ask for a number (or accept an existing path).
# Usage: path="$(lsshm_keys_pick 'Prompt' [require_private=0|1])"
# Echoes the private-key path (without .pub), or empty on cancel.
lsshm_keys_pick() {
    local prompt="${1:-Choisir une clé}"
    local require_priv="${2:-0}"
    local given="${3:-}"

    # Non-interactive / explicit path argument.
    if [ -n "$given" ]; then
        local path="$given"
        case "$path" in *.pub) path="${path%.pub}" ;; esac
        if [ "$require_priv" = "1" ] && [ ! -f "$path" ]; then
            lsshm_error "Clé privée introuvable : $path" >&2
            return 1
        fi
        if [ ! -f "$path.pub" ] && [ ! -f "$path" ]; then
            lsshm_error "Clé introuvable : $given" >&2
            return 1
        fi
        printf '%s' "$path"
        return 0
    fi

    # List on stderr so only the selected path is captured on stdout.
    if ! lsshm_keys_print_numbered >&2; then
        return 1
    fi
    printf '\n' >&2
    local choice; choice="$(lsshm_prompt "$prompt (numéro)" '')"
    if [ -z "$choice" ]; then
        lsshm_info "Annulé." >&2
        return 1
    fi

    # Allow typing a path as fallback.
    if [ -f "$choice" ] || [ -f "$choice.pub" ]; then
        case "$choice" in *.pub) choice="${choice%.pub}" ;; esac
        printf '%s' "$choice"
        return 0
    fi

    case "$choice" in
        ''|*[!0-9]*)
            lsshm_error "Choix invalide : $choice" >&2
            return 1
            ;;
    esac
    if [ "$choice" -lt 1 ] || [ "$choice" -gt "${#LSSHM_KEY_PATHS[@]}" ]; then
        lsshm_error "Numéro hors plage (1-${#LSSHM_KEY_PATHS[@]})." >&2
        return 1
    fi

    local path="${LSSHM_KEY_PATHS[$((choice-1))]}"
    if [ "$require_priv" = "1" ] && [ ! -f "$path" ]; then
        lsshm_error "Clé privée absente pour $(basename "$path")." >&2
        return 1
    fi
    printf '%s' "$path"
    return 0
}

# Generate a new key pair. Default type ED25519.
lsshm_keys_generate() {
    local dir; dir="$(lsshm_keys_dir)"
    lsshm_ensure_user_ssh_dir "$LSSHM_CALLING_USER"

    local type; type="$(lsshm_prompt 'Type de clé (ed25519/rsa)' 'ed25519')"
    case "$type" in
        ed25519|ED25519) type="ed25519" ;;
        rsa|RSA)         type="rsa" ;;
        *)               lsshm_warn "Type inconnu, utilisation de ed25519."; type="ed25519" ;;
    esac

    local default_name="id_$type"
    local name; name="$(lsshm_prompt 'Nom du fichier' "$default_name")"
    local path="$dir/$name"

    if [ -e "$path" ]; then
        lsshm_warn "Le fichier $path existe déjà."
        lsshm_confirm "Écraser ?" no || { lsshm_info "Annulé."; return 1; }
    fi

    local comment; comment="$(lsshm_prompt 'Commentaire' "$LSSHM_CALLING_USER@$(hostname 2>/dev/null || echo host)")"

    local args=(-t "$type" -f "$path" -C "$comment")
    [ "$type" = "rsa" ] && args+=(-b 4096)

    lsshm_info "ssh-keygen ${args[*]}"
    lsshm_info "Une phrase secrète est fortement recommandée."
    if ssh-keygen "${args[@]}"; then
        chmod 600 "$path" 2>/dev/null || true
        chmod 644 "$path.pub" 2>/dev/null || true
        lsshm_chown_user "$LSSHM_CALLING_USER" "$path" "$path.pub"
        lsshm_ok "Clé générée : $path (utilisateur $LSSHM_CALLING_USER)"
        lsshm_info "Clé publique :"
        cat "$path.pub"
    else
        lsshm_error "Échec de la génération."
        return 1
    fi
}

lsshm_keys_inspect() {
    local path
    path="$(lsshm_keys_pick 'Clé à inspecter' 0 "${1:-}")" || return 1
    local pub="$path.pub"
    [ -f "$pub" ] || pub="$path"
    if [ ! -f "$pub" ]; then
        lsshm_error "Fichier introuvable : $pub"
        return 1
    fi
    lsshm_info "Empreinte :"
    ssh-keygen -lf "$pub"
    lsshm_info "Art aléatoire :"
    ssh-keygen -lvf "$pub" 2>/dev/null | tail -n +1 || true
}

lsshm_keys_export() {
    local path
    path="$(lsshm_keys_pick 'Clé à exporter' 0 "${1:-}")" || return 1
    local pub="$path.pub"
    if [ ! -f "$pub" ]; then
        lsshm_error "Clé publique introuvable : $pub"
        return 1
    fi
    lsshm_info "Clé publique ($pub) :"
    cat "$pub"
}

lsshm_keys_passphrase() {
    local path
    path="$(lsshm_keys_pick 'Clé dont la phrase secrète doit être modifiée' 1 "${1:-}")" || return 1
    lsshm_info "Modification de la phrase secrète de $path"
    ssh-keygen -p -f "$path"
}

lsshm_keys_delete() {
    local path
    path="$(lsshm_keys_pick 'Clé à supprimer' 0 "${1:-}")" || return 1
    local priv="$path" pub="$path.pub"

    if [ ! -e "$priv" ] && [ ! -e "$pub" ]; then
        lsshm_error "Aucun fichier de clé trouvé pour : $path"
        return 1
    fi
    lsshm_warn "Suppression de la paire de clés :"
    [ -e "$priv" ] && printf '  %s\n' "$priv"
    [ -e "$pub" ]  && printf '  %s\n' "$pub"
    lsshm_confirm "Une sauvegarde sera créée. Confirmer la suppression ?" no || { lsshm_info "Annulé."; return 0; }

    [ -e "$priv" ] && lsshm_backup_file "$priv" "privkey" >/dev/null 2>&1 || true
    [ -e "$pub" ]  && lsshm_backup_file "$pub" "pubkey" >/dev/null 2>&1 || true
    rm -f "$priv" "$pub"
    lsshm_ok "Paire de clés supprimée (sauvegarde conservée)."
}

# ===== src/ssh_agent.sh ================================================
# shellcheck shell=bash
# =============================================================================
# ssh_agent.sh - manage keys loaded into ssh-agent
# =============================================================================

lsshm_agent_available() {
    if [ -z "${SSH_AUTH_SOCK:-}" ]; then
        lsshm_warn "Aucun ssh-agent détecté (SSH_AUTH_SOCK non défini)."
        lsshm_info "Démarrez un agent : eval \"\$(ssh-agent -s)\""
        return 1
    fi
    return 0
}

lsshm_agent_list() {
    lsshm_agent_available || return 1
    local tmp; tmp="$(lsshm_mktemp)"
    if ssh-add -l >"$tmp" 2>&1; then
        lsshm_info "Clés chargées dans ssh-agent :"
        cat "$tmp"
    else
        lsshm_info "$(cat "$tmp")"
    fi
}

lsshm_agent_add() {
    local path="${1:-}"
    lsshm_agent_available || return 1
    path="$(lsshm_keys_pick 'Clé à ajouter à ssh-agent' 1 "$path")" || return 1
    ssh-add "$path" && lsshm_ok "Clé ajoutée à ssh-agent."
}

lsshm_agent_remove() {
    local path="${1:-}"
    lsshm_agent_available || return 1
    if [ -z "$path" ]; then
        if lsshm_confirm "Retirer toutes les clés de l'agent ?" no; then
            ssh-add -D && lsshm_ok "Toutes les clés retirées."
            return 0
        fi
    fi
    path="$(lsshm_keys_pick 'Clé à retirer de ssh-agent' 1 "$path")" || return 1
    ssh-add -d "$path" && lsshm_ok "Clé retirée de ssh-agent."
}

# ===== src/hosts.sh ====================================================
# shellcheck shell=bash
# =============================================================================
# hosts.sh - remote machines managed through ~/.ssh/config (OPTIONAL feature)
# =============================================================================
# These are outgoing connection targets. LSSHM remains fully usable with no
# host configured.

lsshm_hosts_file() {
    printf '%s/config' "$(lsshm_target_ssh_dir)"
}

lsshm_hosts_list() {
    local file; file="$(lsshm_hosts_file)"
    if [ ! -f "$file" ]; then
        lsshm_info "Aucun fichier ~/.ssh/config."
        return 0
    fi
    lsshm_info "Machines distantes enregistrées ($file) :"
    local count=0 name hostname
    while IFS= read -r name; do
        [ -n "$name" ] || continue
        case "$name" in *'*'*|*'?'*) continue ;; esac
        count=$((count+1))
        hostname="$(lsshm_hosts_get_field "$name" HostName)"
        printf '  %-20s %s\n' "$name" "${hostname:-}"
    done <<EOF
$(awk 'tolower($1)=="host"{for(i=2;i<=NF;i++)print $i}' "$file")
EOF
    [ "$count" = "0" ] && lsshm_info "  (aucune)"
}

lsshm_hosts_count() {
    local file; file="$(lsshm_hosts_file)"
    [ -f "$file" ] || { printf '0'; return; }
    awk 'tolower($1)=="host"{for(i=2;i<=NF;i++){if($i!~/[*?]/)c++}}END{print c+0}' "$file"
}

# Get a field value from a Host block in the config file.
lsshm_hosts_get_field() {
    local name="$1" field="$2" file
    file="$(lsshm_hosts_file)"
    [ -f "$file" ] || return 1
    awk -v want="$name" -v f="$(printf '%s' "$field" | tr '[:upper:]' '[:lower:]')" '
        tolower($1)=="host" { inblk=0; for(i=2;i<=NF;i++) if($i==want) inblk=1; next }
        inblk && tolower($1)==f { $1=""; sub(/^ /,""); print; exit }
    ' "$file"
}

lsshm_hosts_exists() {
    local name="$1" file
    file="$(lsshm_hosts_file)"
    [ -f "$file" ] || return 1
    awk -v want="$name" 'tolower($1)=="host"{for(i=2;i<=NF;i++) if($i==want){found=1}} END{exit(found?0:1)}' "$file"
}

lsshm_hosts_add() {
    local file; file="$(lsshm_hosts_file)"
    lsshm_ensure_user_ssh_dir "$LSSHM_CALLING_USER"

    local name hostname user port identity proxyjump
    name="$(lsshm_prompt 'Nom (alias) de la machine' 'proxmox1')"
    [ -n "$name" ] || { lsshm_error "Nom requis."; return 1; }
    if lsshm_hosts_exists "$name"; then
        lsshm_error "Un hôte nommé '$name' existe déjà."
        return 1
    fi
    hostname="$(lsshm_prompt 'Adresse (HostName)' '192.168.100.240')"
    user="$(lsshm_prompt 'Utilisateur' 'root')"
    port="$(lsshm_prompt 'Port' '22')"
    identity="$(lsshm_prompt 'Fichier de clé (IdentityFile)' "$(lsshm_keys_dir)/id_ed25519")"
    proxyjump="$(lsshm_prompt 'ProxyJump (vide = aucun)' '')"

    {
        printf '\nHost %s\n' "$name"
        printf '    HostName %s\n' "$hostname"
        printf '    User %s\n' "$user"
        printf '    Port %s\n' "$port"
        printf '    IdentityFile %s\n' "$identity"
        printf '    IdentitiesOnly yes\n'
        [ -n "$proxyjump" ] && printf '    ProxyJump %s\n' "$proxyjump"
    } >>"$file"
    chmod 600 "$file" 2>/dev/null || true
    lsshm_chown_user "$LSSHM_CALLING_USER" "$file"
    lsshm_ok "Hôte '$name' ajouté à $file"
}

lsshm_hosts_delete() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte à supprimer' '')"
    [ -n "$name" ] || { lsshm_info "Annulé."; return 0; }
    local file; file="$(lsshm_hosts_file)"
    [ -f "$file" ] || { lsshm_error "Aucun fichier config."; return 1; }
    lsshm_hosts_exists "$name" || { lsshm_error "Hôte introuvable : $name"; return 1; }

    lsshm_backup_file "$file" "ssh-config" >/dev/null 2>&1 || true
    local tmp; tmp="$(lsshm_mktemp)"
    awk -v want="$name" '
        tolower($1)=="host" {
            skip=0; for(i=2;i<=NF;i++) if($i==want) skip=1;
            if(skip){inblk=1; next} else {inblk=0}
        }
        !inblk { print }
    ' "$file" >"$tmp"
    install -m 0600 "$tmp" "$file"
    lsshm_ok "Hôte '$name' supprimé."
}

lsshm_hosts_edit() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte à modifier' '')"
    lsshm_hosts_exists "$name" || { lsshm_error "Hôte introuvable : $name"; return 1; }
    lsshm_info "Configuration actuelle de '$name' :"
    lsshm_hosts_show "$name"
    lsshm_warn "L'édition remplace le bloc complet."
    lsshm_confirm "Continuer ?" no || return 0
    lsshm_hosts_delete "$name"
    lsshm_hosts_add
}

lsshm_hosts_show() {
    local name="$1"
    printf '  HostName    : %s\n' "$(lsshm_hosts_get_field "$name" HostName)"
    printf '  User        : %s\n' "$(lsshm_hosts_get_field "$name" User)"
    printf '  Port        : %s\n' "$(lsshm_hosts_get_field "$name" Port)"
    printf '  IdentityFile: %s\n' "$(lsshm_hosts_get_field "$name" IdentityFile)"
    printf '  ProxyJump   : %s\n' "$(lsshm_hosts_get_field "$name" ProxyJump)"
}

lsshm_hosts_effective() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte' '')"
    lsshm_have ssh || { lsshm_error "ssh introuvable."; return 1; }
    lsshm_info "Configuration effective (ssh -G $name) :"
    ssh -G "$name" 2>/dev/null | grep -Ei '^(hostname|user|port|identityfile|proxyjump) '
}

lsshm_hosts_test() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte à tester' '')"
    local host port
    host="$(lsshm_hosts_get_field "$name" HostName)"; host="${host:-$name}"
    port="$(lsshm_hosts_get_field "$name" Port)"; port="${port:-22}"

    lsshm_info "Test de résolution de $host..."
    if lsshm_have getent && getent hosts "$host" >/dev/null 2>&1; then
        lsshm_ok "Résolution DNS réussie."
    else
        lsshm_warn "Résolution DNS incertaine."
    fi

    lsshm_info "Test du port $port..."
    if lsshm_have nc && nc -z -w 3 "$host" "$port" 2>/dev/null; then
        lsshm_ok "Port $port ouvert."
    elif (exec 3<>"/dev/tcp/$host/$port") 2>/dev/null; then
        lsshm_ok "Port $port ouvert."
        exec 3>&- 2>/dev/null || true
    else
        lsshm_warn "Port $port injoignable."
    fi

    lsshm_info "Test d'authentification SSH (BatchMode)..."
    if ssh -o BatchMode=yes -o ConnectTimeout=5 "$name" true 2>/dev/null; then
        lsshm_ok "Authentification réussie."
    else
        lsshm_warn "Authentification non automatique (clé manquante ou mot de passe requis)."
    fi
}

lsshm_hosts_connect() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte' '')"
    [ -n "$name" ] || return 1
    lsshm_info "Connexion à $name..."
    ssh "$name"
}

lsshm_hosts_copy_key() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte' '')"
    lsshm_have ssh-copy-id || { lsshm_error "ssh-copy-id introuvable."; return 1; }
    local identity; identity="$(lsshm_hosts_get_field "$name" IdentityFile)"
    identity="${identity:-$(lsshm_keys_dir)/id_ed25519}"
    local pub="$identity.pub"
    [ -f "$pub" ] || { lsshm_error "Clé publique introuvable : $pub"; return 1; }
    lsshm_info "Copie de $pub vers $name..."
    ssh-copy-id -i "$pub" "$name"
}

lsshm_hosts_revoke_key() {
    local name="$1"
    [ -n "$name" ] || name="$(lsshm_prompt 'Nom de l’hôte' '')"
    [ -n "$name" ] || { lsshm_info "Annulé."; return 0; }
    local identity; identity="$(lsshm_hosts_get_field "$name" IdentityFile)"
    identity="${identity:-$(lsshm_keys_dir)/id_ed25519}"
    # Expand a leading ~/ in IdentityFile (literal prefix, not shell tilde expansion).
    if [ "${identity#~/}" != "$identity" ]; then
        identity="$HOME/${identity#~/}"
    fi
    local pub="$identity.pub"
    [ -f "$pub" ] || { lsshm_error "Clé publique introuvable : $pub"; return 1; }
    local keytext; keytext="$(awk '{print $2}' "$pub")"
    [ -n "$keytext" ] || { lsshm_error "Corps de clé publique vide."; return 1; }
    # OpenSSH key bodies are base64; reject anything else before remote use.
    case "$keytext" in
        *[!A-Za-z0-9+/=]*)
            lsshm_error "Corps de clé invalide (caractères inattendus)."
            return 1
            ;;
    esac
    lsshm_warn "Retrait de la clé sur $name (nécessite un accès autorisé)."
    lsshm_confirm "Continuer ?" no || return 0
    # Exact field match via awk (not grep regex). Key passed as env, not shell-interpolated.
    if KEYBLOB="$keytext" ssh "$name" 'bash -s' <<'REMOTE'
set -euo pipefail
ak="${HOME}/.ssh/authorized_keys"
[ -f "$ak" ] || { echo "authorized_keys introuvable" >&2; exit 1; }
tmp="$(mktemp "${HOME}/.ssh/authorized_keys.lsshm.XXXXXX")"
awk -v k="$KEYBLOB" '
{
  keep=1
  for (i=1; i<=NF; i++) if ($i == k) keep=0
  if (keep) print
}' "$ak" >"$tmp"
mv "$tmp" "$ak"
chmod 600 "$ak"
REMOTE
    then
        lsshm_ok "Clé retirée sur $name."
    else
        lsshm_error "Échec du retrait."
        return 1
    fi
}

# ===== src/known_hosts.sh ==============================================
# shellcheck shell=bash
# =============================================================================
# known_hosts.sh - manage ~/.ssh/known_hosts fingerprints
# =============================================================================

lsshm_known_hosts_file() {
    printf '%s/known_hosts' "$(lsshm_target_ssh_dir)"
}

lsshm_known_hosts_list() {
    local file; file="$(lsshm_known_hosts_file)"
    if [ ! -f "$file" ]; then
        lsshm_info "Aucun fichier known_hosts."
        return 0
    fi
    lsshm_info "Empreintes connues ($file) :"
    ssh-keygen -lf "$file" 2>/dev/null || awk '{print $1}' "$file"
}

lsshm_known_hosts_show() {
    local host="$1"
    [ -n "$host" ] || host="$(lsshm_prompt 'Nom ou adresse du serveur' '')"
    [ -n "$host" ] || return 1
    lsshm_info "Empreinte hôte pour $host :"
    ssh-keygen -F "$host" 2>/dev/null || lsshm_warn "Aucune entrée pour $host."
}

lsshm_known_hosts_remove() {
    local host="$1"
    [ -n "$host" ] || host="$(lsshm_prompt 'Hôte à supprimer de known_hosts' '')"
    [ -n "$host" ] || { lsshm_info "Annulé."; return 0; }
    local file; file="$(lsshm_known_hosts_file)"
    [ -f "$file" ] || { lsshm_error "Aucun fichier known_hosts."; return 1; }
    lsshm_backup_file "$file" "known-hosts" >/dev/null 2>&1 || true
    if ssh-keygen -R "$host" -f "$file" >/dev/null 2>&1; then
        lsshm_ok "Empreinte de $host supprimée."
    else
        lsshm_error "Échec de la suppression pour $host."
        return 1
    fi
}

lsshm_known_hosts_scan() {
    local host="$1"
    [ -n "$host" ] || host="$(lsshm_prompt 'Hôte à scanner' '')"
    [ -n "$host" ] || return 1
    lsshm_have ssh-keyscan || { lsshm_error "ssh-keyscan introuvable."; return 1; }
    lsshm_info "Empreinte annoncée par $host :"
    ssh-keyscan "$host" 2>/dev/null | ssh-keygen -lf - 2>/dev/null
}

# ===== src/logs.sh =====================================================
# shellcheck shell=bash
# =============================================================================
# logs.sh - sessions, logins, and SSH service logs
# =============================================================================

lsshm_logs_sessions() {
    lsshm_info "Sessions SSH actives :"
    if lsshm_have who; then
        who 2>/dev/null | grep -Ei 'pts|ssh' || who 2>/dev/null || lsshm_info "  (aucune)"
    else
        lsshm_warn "'who' indisponible."
    fi
}

lsshm_logs_recent_logins() {
    lsshm_info "Connexions récentes :"
    if lsshm_have last; then
        lsshm_run_privileged last -n 10 2>/dev/null | head -n 10 || true
    else
        lsshm_warn "'last' indisponible."
    fi
}

lsshm_logs_failed() {
    lsshm_info "Tentatives de connexion échouées récentes :"
    if lsshm_have lastb; then
        lsshm_run_privileged lastb -n 10 2>/dev/null | head -n 10 || lsshm_info "  (aucune ou non accessible)"
    elif [ -f /var/log/auth.log ]; then
        lsshm_run_privileged grep -i 'failed password' /var/log/auth.log 2>/dev/null | tail -n 10 || lsshm_info "  (aucune)"
    else
        lsshm_warn "Aucune source de tentatives échouées disponible."
    fi
}

lsshm_logs_service() {
    lsshm_info "Journaux du service SSH :"
    lsshm_server_logs 40
}

lsshm_logs_menu() {
    while true; do
        local choice="" pick_ret=0
        if lsshm_uses_dialog_ui; then
            choice="$(lsshm_dialog_logs_menu)" || pick_ret=$?
            [ "$pick_ret" -ne 0 ] && break
        else
            clear 2>/dev/null || true
            lsshm_header
            printf 'Connexions et journaux\n\n'
            cat <<EOF
  1. Sessions actives
  2. Connexions récentes
  3. Tentatives échouées
  4. Journaux du service SSH
  5. Retour
EOF
            choice="$(lsshm_prompt 'Choix' '5')"
        fi
        case "$choice" in
            1) lsshm_ui_run "Sessions actives" lsshm_logs_sessions ;;
            2) lsshm_ui_run "Connexions récentes" lsshm_logs_recent_logins ;;
            3) lsshm_ui_run "Tentatives échouées" lsshm_logs_failed ;;
            4) lsshm_ui_run "Journaux SSH" lsshm_logs_service ;;
            5|q|Q) break ;;
            *) lsshm_warn "Choix invalide."; lsshm_uses_dialog_ui || lsshm_pause ;;
        esac
    done
}

# ===== src/audit.sh ====================================================
# shellcheck shell=bash
# =============================================================================
# audit.sh - local SSH security audit and diagnostics
# =============================================================================

LSSHM_AUDIT_PASS=0
LSSHM_AUDIT_WARN=0
LSSHM_AUDIT_FAIL=0

lsshm_audit_pass() { LSSHM_AUDIT_PASS=$((LSSHM_AUDIT_PASS+1)); printf '  [%sOK%s]   %s\n' "${LSSHM_C_GREEN:-}" "${LSSHM_C_RESET:-}" "$*"; }
lsshm_audit_warn() { LSSHM_AUDIT_WARN=$((LSSHM_AUDIT_WARN+1)); printf '  [%sAVERT%s] %s\n' "${LSSHM_C_YELLOW:-}" "${LSSHM_C_RESET:-}" "$*"; }
lsshm_audit_fail() { LSSHM_AUDIT_FAIL=$((LSSHM_AUDIT_FAIL+1)); printf '  [%sÉCHEC%s] %s\n' "${LSSHM_C_RED:-}" "${LSSHM_C_RESET:-}" "$*"; }

lsshm_audit() {
    LSSHM_AUDIT_PASS=0; LSSHM_AUDIT_WARN=0; LSSHM_AUDIT_FAIL=0
    lsshm_header
    printf 'Audit de sécurité SSH local\n\n'

    printf '%sServeur SSH%s\n' "${LSSHM_C_BOLD:-}" "${LSSHM_C_RESET:-}"
    if lsshm_server_is_installed; then
        lsshm_audit_pass "OpenSSH Server installé."
    else
        lsshm_audit_warn "OpenSSH Server non installé."
    fi

    local root pass maxauth
    root="$(lsshm_server_config_effective_value permitrootlogin)"
    case "$root" in
        no) lsshm_audit_pass "PermitRootLogin = no (root interdit)." ;;
        prohibit-password|without-password) lsshm_audit_pass "PermitRootLogin = clé uniquement." ;;
        yes) lsshm_audit_fail "PermitRootLogin = yes (root avec mot de passe autorisé)." ;;
        *) lsshm_audit_warn "PermitRootLogin = ${root:-non défini}." ;;
    esac

    pass="$(lsshm_server_config_effective_value passwordauthentication)"
    case "$pass" in
        no) lsshm_audit_pass "Authentification par mot de passe désactivée." ;;
        yes) lsshm_audit_warn "Authentification par mot de passe activée." ;;
        *) lsshm_audit_warn "PasswordAuthentication = ${pass:-non défini}." ;;
    esac

    maxauth="$(lsshm_server_config_effective_value maxauthtries)"
    if [ -n "$maxauth" ] && [ "$maxauth" -le 4 ] 2>/dev/null; then
        lsshm_audit_pass "MaxAuthTries = $maxauth."
    else
        lsshm_audit_warn "MaxAuthTries = ${maxauth:-défaut} (recommandé <= 4)."
    fi

    if lsshm_server_is_installed && lsshm_server_config_test >/dev/null 2>&1; then
        lsshm_audit_pass "sshd -t : configuration valide."
    elif lsshm_server_is_installed; then
        lsshm_audit_fail "sshd -t : configuration invalide."
    fi

    printf '\n%sPermissions locales (%s)%s\n' "${LSSHM_C_BOLD:-}" "$LSSHM_CALLING_USER" "${LSSHM_C_RESET:-}"
    local ssh_dir; ssh_dir="$(lsshm_target_ssh_dir)"
    if [ -d "$ssh_dir" ]; then
        local perm; perm="$(stat -c '%a' "$ssh_dir" 2>/dev/null || stat -f '%Lp' "$ssh_dir" 2>/dev/null)"
        if [ "$perm" = "700" ]; then
            lsshm_audit_pass "Le dossier .ssh a les permissions 700."
        else
            lsshm_audit_warn "Le dossier .ssh a les permissions ${perm:-inconnues} (attendu 700)."
        fi
        local ak="$ssh_dir/authorized_keys"
        if [ -f "$ak" ]; then
            perm="$(stat -c '%a' "$ak" 2>/dev/null || stat -f '%Lp' "$ak" 2>/dev/null)"
            [ "$perm" = "600" ] && lsshm_audit_pass "authorized_keys 600." \
                || lsshm_audit_warn "authorized_keys ${perm:-inconnu} (attendu 600)."
        fi
        local priv
        for priv in "$ssh_dir"/id_*; do
            [ -f "$priv" ] || continue
            case "$priv" in *.pub) continue ;; esac
            perm="$(stat -c '%a' "$priv" 2>/dev/null || stat -f '%Lp' "$priv" 2>/dev/null)"
            [ "$perm" = "600" ] && lsshm_audit_pass "$(basename "$priv") 600." \
                || lsshm_audit_fail "$(basename "$priv") ${perm:-inconnu} (clé privée doit être 600)."
        done
    else
        lsshm_audit_warn "Aucun répertoire .ssh pour $LSSHM_CALLING_USER."
    fi

    printf '\n%sPort d’écoute%s\n' "${LSSHM_C_BOLD:-}" "${LSSHM_C_RESET:-}"
    if lsshm_server_port_listening; then
        lsshm_audit_pass "Le port SSH configuré écoute."
    else
        lsshm_audit_warn "Impossible de confirmer l'écoute du port SSH."
    fi

    printf '\n%sRésumé%s : %d OK, %d avertissements, %d échecs\n' \
        "${LSSHM_C_BOLD:-}" "${LSSHM_C_RESET:-}" \
        "$LSSHM_AUDIT_PASS" "$LSSHM_AUDIT_WARN" "$LSSHM_AUDIT_FAIL"

    [ "$LSSHM_AUDIT_FAIL" -eq 0 ]
}

# Doctor: environment and configuration diagnostics.
lsshm_doctor() {
    lsshm_header
    printf 'Diagnostic LSSHM (doctor)\n\n'
    lsshm_platform_summary
    printf '\n'
    lsshm_info "Outils SSH :"
    local t
    for t in ssh sshd ssh-keygen ssh-add ssh-copy-id ssh-keyscan; do
        if lsshm_have "$t"; then printf '  [OK]  %s\n' "$t"; else printf '  [--]  %s (absent)\n' "$t"; fi
    done
    printf '\n'
    lsshm_info "Chemins LSSHM :"
    printf '  config : %s\n' "$LSSHM_CONFIG_DIR"
    printf '  data   : %s\n' "$LSSHM_DATA_DIR"
    printf '  state  : %s\n' "$LSSHM_STATE_DIR"
    printf '  cache  : %s\n' "$LSSHM_CACHE_DIR"
    printf '\n'
    lsshm_info "PATH :"
    case ":$PATH:" in
        *":$LSSHM_BIN_DIR:"*) printf '  [OK]  %s est dans le PATH\n' "$LSSHM_BIN_DIR" ;;
        *) printf '  [--]  %s absent du PATH\n' "$LSSHM_BIN_DIR" ;;
    esac
}

# ===== src/updater.sh ==================================================
# shellcheck shell=bash
# =============================================================================
# updater.sh - configuration file and safe self-update
# =============================================================================

# --- configuration file (INI-style key=value) --------------------------------

lsshm_config_default() {
    cat <<EOF
# LSSHM configuration
update_check=daily
update_channel=stable
EOF
}

lsshm_config_load() {
    LSSHM_CFG_UPDATE_CHECK="daily"
    LSSHM_CFG_UPDATE_CHANNEL="stable"
    [ -r "$LSSHM_CONFIG_FILE" ] || return 0
    local line key val
    while IFS= read -r line; do
        case "$line" in ''|'#'*) continue ;; esac
        key="${line%%=*}"; val="${line#*=}"
        key="$(printf '%s' "$key" | tr -d '[:space:]')"
        case "$key" in
            update_check)   LSSHM_CFG_UPDATE_CHECK="$val" ;;
            update_channel) LSSHM_CFG_UPDATE_CHANNEL="$val" ;;
        esac
    done <"$LSSHM_CONFIG_FILE"
}

lsshm_config_write_default() {
    lsshm_ensure_dirs
    [ -f "$LSSHM_CONFIG_FILE" ] && return 0
    lsshm_config_default >"$LSSHM_CONFIG_FILE"
}

lsshm_config_set() {
    local key="$1" value="$2"
    lsshm_ensure_dirs
    [ -f "$LSSHM_CONFIG_FILE" ] || lsshm_config_default >"$LSSHM_CONFIG_FILE"
    local tmp; tmp="$(lsshm_mktemp)"
    if grep -q "^${key}=" "$LSSHM_CONFIG_FILE" 2>/dev/null; then
        sed "s|^${key}=.*|${key}=${value}|" "$LSSHM_CONFIG_FILE" >"$tmp"
    else
        cat "$LSSHM_CONFIG_FILE" >"$tmp"
        printf '%s=%s\n' "$key" "$value" >>"$tmp"
    fi
    install -m 0644 "$tmp" "$LSSHM_CONFIG_FILE"
}

# --- download helpers --------------------------------------------------------

lsshm_download() {
    # lsshm_download URL OUTFILE
    local url="$1" out="$2"
    if lsshm_have curl; then
        curl -fsSL "$url" -o "$out"
    elif lsshm_have wget; then
        wget -qO "$out" "$url"
    else
        lsshm_error "Ni curl ni wget disponibles pour le téléchargement."
        return 1
    fi
}

lsshm_remote_version() {
    local tmp; tmp="$(lsshm_mktemp)"
    if lsshm_download "$LSSHM_REPO_RAW/VERSION" "$tmp" 2>/dev/null; then
        tr -d '[:space:]' <"$tmp"
    fi
}

lsshm_version_gt() {
    # returns 0 if $1 > $2 (semantic-ish numeric compare)
    [ "$1" = "$2" ] && return 1
    local greater
    greater="$(printf '%s\n%s\n' "$1" "$2" | sort -V | tail -n1)"
    [ "$greater" = "$1" ]
}

# --- update check ------------------------------------------------------------

lsshm_update_stamp() { printf '%s/last_update_check' "$LSSHM_CACHE_DIR"; }

lsshm_update_should_check() {
    lsshm_config_load
    case "$LSSHM_CFG_UPDATE_CHECK" in
        never) return 1 ;;
        always) return 0 ;;
        daily|*)
            local stamp; stamp="$(lsshm_update_stamp)"
            [ -f "$stamp" ] || return 0
            local last now
            last="$(cat "$stamp" 2>/dev/null || echo 0)"
            now="$(date +%s)"
            [ $((now - last)) -ge 86400 ]
            ;;
    esac
}

lsshm_update_touch_stamp() {
    lsshm_ensure_dirs
    date +%s >"$(lsshm_update_stamp)" 2>/dev/null || true
}

# Light check performed at startup.
lsshm_update_check() {
    lsshm_update_should_check || return 0
    lsshm_update_touch_stamp
    local remote; remote="$(lsshm_remote_version)"
    [ -n "$remote" ] || return 0
    if lsshm_version_gt "$remote" "$LSSHM_VERSION"; then
        printf '\nVersion installée : %s\n' "$LSSHM_VERSION"
        printf 'Version disponible : %s\n\n' "$remote"
        printf 'Une mise à jour est disponible.\n'
        if lsshm_confirm "Installer maintenant ?" no; then
            lsshm_update_run
        fi
    fi
}

# --- safe update -------------------------------------------------------------

lsshm_update_run() {
    lsshm_ensure_dirs
    local target="$LSSHM_INSTALL_TARGET"
    if [ ! -f "$target" ]; then
        lsshm_warn "LSSHM ne semble pas installé dans $target."
        lsshm_info "Utilisez : curl -fsSL $LSSHM_REPO_RAW/lsshm.sh | bash -s -- install"
        return 1
    fi

    local remote; remote="$(lsshm_remote_version)"
    lsshm_info "Version installée : $LSSHM_VERSION"
    lsshm_info "Version distante  : ${remote:-inconnue}"

    # 1. Download to a temporary file.
    local tmp; tmp="$(lsshm_mktemp)"
    lsshm_info "Téléchargement de la nouvelle version..."
    if ! lsshm_download "$LSSHM_REPO_RAW/lsshm.sh" "$tmp"; then
        lsshm_error "Échec du téléchargement."
        return 1
    fi

    # 2. Validate syntax with bash -n.
    if ! bash -n "$tmp"; then
        lsshm_error "Le script téléchargé contient des erreurs de syntaxe. Abandon."
        return 1
    fi

    # 3. Verify SHA-256 against the published SHA256SUMS.
    if ! lsshm_update_verify_checksum "$tmp"; then
        lsshm_error "Vérification SHA-256 échouée. Abandon."
        return 1
    fi

    # 4. Sanity check: the new file must identify itself as LSSHM.
    if ! grep -q "LSSHM" "$tmp"; then
        lsshm_error "Le fichier téléchargé ne ressemble pas à LSSHM. Abandon."
        return 1
    fi

    # 5/6. Keep previous version, then replace atomically.
    cp -a "$target" "$target.prev" 2>/dev/null || true
    chmod +x "$tmp"
    if install -m 0755 "$tmp" "$target"; then
        lsshm_ok "Mise à jour installée. Version précédente conservée : $target.prev"
        lsshm_info "Utilisez 'lsshm update rollback' pour revenir en arrière."
    else
        lsshm_error "Échec du remplacement du fichier."
        return 1
    fi
}

# Fail-closed: any missing tool, missing file, or mismatch aborts the caller.
lsshm_update_verify_checksum() {
    local file="$1"
    if [ ! -f "$file" ]; then
        lsshm_error "Fichier à vérifier introuvable."
        return 1
    fi
    local sums; sums="$(lsshm_mktemp)"
    if ! lsshm_download "$LSSHM_REPO_RAW/SHA256SUMS" "$sums" 2>/dev/null; then
        lsshm_error "SHA256SUMS indisponible : vérification impossible (abandon)."
        return 1
    fi
    local expected actual
    # Accept both text ("hash  lsshm.sh") and binary ("hash *lsshm.sh") formats.
    expected="$(awk '
        {
            f = $2
            sub(/^\*/, "", f)
            if (f == "lsshm.sh") { print $1; exit }
        }
    ' "$sums")"
    if [ -z "$expected" ]; then
        lsshm_error "Empreinte lsshm.sh absente de SHA256SUMS (abandon)."
        return 1
    fi
    if lsshm_have sha256sum; then
        actual="$(sha256sum "$file" | awk '{print $1}')"
    elif lsshm_have shasum; then
        actual="$(shasum -a 256 "$file" | awk '{print $1}')"
    else
        lsshm_error "Aucun outil SHA-256 (sha256sum/shasum) : vérification impossible (abandon)."
        return 1
    fi
    if [ "$expected" != "$actual" ]; then
        lsshm_error "Empreinte SHA-256 incorrecte."
        lsshm_error "  attendu : $expected"
        lsshm_error "  obtenu  : $actual"
        return 1
    fi
    lsshm_ok "Empreinte SHA-256 vérifiée."
    return 0
}

lsshm_update_rollback() {
    local target="$LSSHM_INSTALL_TARGET"
    if [ ! -f "$target.prev" ]; then
        lsshm_error "Aucune version précédente disponible ($target.prev)."
        return 1
    fi
    lsshm_confirm "Restaurer la version précédente de LSSHM ?" no || { lsshm_info "Annulé."; return 0; }
    if install -m 0755 "$target.prev" "$target"; then
        lsshm_ok "Version précédente restaurée."
    else
        lsshm_error "Échec de la restauration."
        return 1
    fi
}

# ===== src/cli.sh ======================================================
# shellcheck shell=bash
# =============================================================================
# cli.sh - dependency-free CLI menus
# =============================================================================

# The status panel shown at the top of the main menu.
# Must not prompt for sudo: uses cached/non-interactive sshd -T or file parse.
lsshm_status_panel() {
    local active port root pass rootkeys userkeys hosts dump
    if lsshm_server_is_installed && lsshm_server_is_active; then active="actif"; else active="inactif"; fi

    # One dump (or none) for all status fields — never three sudo prompts.
    dump="$(lsshm_server_config_dump)" || dump=""
    if [ -n "$dump" ]; then
        port="$(printf '%s\n' "$dump" | awk 'tolower($1)=="port"{sub($1 FS,""); print; exit}')"
        root="$(printf '%s\n' "$dump" | awk 'tolower($1)=="permitrootlogin"{sub($1 FS,""); print; exit}')"
        pass="$(printf '%s\n' "$dump" | awk 'tolower($1)=="passwordauthentication"{sub($1 FS,""); print; exit}')"
    else
        port="$(lsshm_config_parse_value port)"
        root="$(lsshm_config_parse_value permitrootlogin)"
        pass="$(lsshm_config_parse_value passwordauthentication)"
    fi
    port="${port:-22}"
    root="$(lsshm_rootlogin_label "$root")"
    pass="$(lsshm_yesno_label "$pass")"

    rootkeys="$(lsshm_user_key_count root)"
    userkeys="0"
    local kd; kd="$(lsshm_keys_dir)"
    if [ -d "$kd" ]; then
        userkeys="$(find "$kd" -maxdepth 1 -type f -name 'id_*' ! -name '*.pub' 2>/dev/null | wc -l | tr -d ' ')"
    fi
    hosts="$(lsshm_hosts_count)"

    cat <<EOF
Utilisateur administré : $LSSHM_CALLING_USER
État du serveur SSH : $active
Port : $port
Accès root : $root
Authentification par mot de passe : $pass
Clés autorisées pour root : $rootkeys
Clés privées de $LSSHM_CALLING_USER : $userkeys
Machines distantes enregistrées : $hosts
EOF
}

lsshm_cli_main() {
    lsshm_require_interactive
    while true; do
        clear 2>/dev/null || true
        lsshm_header
        lsshm_status_panel
        cat <<EOF

1. Gérer le serveur SSH local
2. Gérer les accès à cette machine
3. Gérer mes clés SSH
4. Gérer les machines distantes
5. Consulter les connexions et journaux
6. Effectuer un audit de sécurité
7. Sauvegarder ou restaurer
8. Paramètres de LSSHM
9. Quitter
EOF
        local choice; choice="$(lsshm_prompt 'Choix' '9')"
        case "$choice" in
            1) lsshm_cli_server_menu ;;
            2) lsshm_cli_access_menu ;;
            3) lsshm_cli_keys_menu ;;
            4) lsshm_cli_hosts_menu ;;
            5) lsshm_logs_menu ;;
            6) lsshm_audit; lsshm_pause ;;
            7) lsshm_backup_menu ;;
            8) lsshm_settings_menu ;;
            9|q|Q) break ;;
            *) lsshm_warn "Choix invalide." ; lsshm_pause ;;
        esac
    done
}

# --- server menu -------------------------------------------------------------

lsshm_cli_server_menu() {
    while true; do
        local choice="" pick_ret=0
